1	-------------------------------------------------------------------------------
2	-- Title      : SRPv3 Protocol: https://confluence.slac.stanford.edu/x/cRmVD
3	-------------------------------------------------------------------------------
4	-- Company    : SLAC National Accelerator Laboratory
5	-------------------------------------------------------------------------------
6	-- Description: SLAC Register Protocol Version 3, Core FSM Logic
7	-------------------------------------------------------------------------------
8	-- This file is part of 'SLAC Firmware Standard Library'.
9	-- It is subject to the license terms in the LICENSE.txt file found in the
10	-- top-level directory of this distribution and at:
11	--    https://confluence.slac.stanford.edu/display/ppareg/LICENSE.html.
12	-- No part of 'SLAC Firmware Standard Library', including this file,
13	-- may be copied, modified, propagated, or distributed except according to
14	-- the terms contained in the LICENSE.txt file.
15	-------------------------------------------------------------------------------
16	
17	library ieee;
18	use ieee.std_logic_1164.all;
19	use ieee.std_logic_arith.all;
20	use ieee.std_logic_unsigned.all;
21	
22	library surf;
23	use surf.StdRtlPkg.all;
24	use surf.AxiStreamPkg.all;
25	use surf.SsiPkg.all;
26	use surf.AxiLitePkg.all;
27	use surf.SrpV3Pkg.all;
28	
29	entity SrpV3Core is
30	   generic (
31	      TPD_G               : time                    := 1 ns;
32	      PIPE_STAGES_G       : natural range 0 to 16   := 1;
33	      SYNTH_MODE_G        : string                  := "inferred";
34	      FIFO_PAUSE_THRESH_G : positive range 1 to 511 := 256;
35	      TX_VALID_THOLD_G    : positive                := 1;
36	      SLAVE_READY_EN_G    : boolean                 := false;
37	      GEN_SYNC_FIFO_G     : boolean                 := false;
38	      SRP_CLK_FREQ_G      : real                    := 156.25E+6;  -- units of Hz
39	      AXI_STREAM_CONFIG_G : AxiStreamConfigType;
40	      UNALIGNED_ACCESS_G  : boolean                 := false;
41	      BYTE_ACCESS_G       : boolean                 := false;
42	      WRITE_EN_G          : boolean                 := true;  -- Write ops enabled
43	      READ_EN_G           : boolean                 := true);  -- Read ops enabled
44	   port (
45	      -- AXIS Slave Interface (sAxisClk domain)
46	      sAxisClk    : in  sl;
47	      sAxisRst    : in  sl;
48	      sAxisMaster : in  AxiStreamMasterType;
49	      sAxisSlave  : out AxiStreamSlaveType;
50	      sAxisCtrl   : out AxiStreamCtrlType;
51	      -- AXIS Master Interface (mAxisClk domain)
52	      mAxisClk    : in  sl;
53	      mAxisRst    : in  sl;
54	      mAxisMaster : out AxiStreamMasterType;
55	      mAxisSlave  : in  AxiStreamSlaveType;
56	      -- Master AXI-Lite Interface (axilClk domain)
57	      srpClk      : in  sl;
58	      srpRst      : in  sl;
59	      srpReq      : out SrpV3ReqType;
60	      srpAck      : in  SrpV3AckType;
61	      srpWrMaster : out AxiStreamMasterType;
62	      srpWrSlave  : in  AxiStreamSlaveType;
63	      srpRdMaster : in  AxiStreamMasterType;
64	      srpRdSlave  : out AxiStreamSlaveType);
65	end SrpV3Core;
66	
67	architecture rtl of SrpV3Core is
68	
69	   constant TIMEOUT_C : natural := (getTimeRatio(SRP_CLK_FREQ_G, 10.0) - 1);  -- 100 ms timeout
70	
71	   constant SRP_AXIS_CONFIG_C : AxiStreamConfigType := (
72	      TSTRB_EN_C    => false,
73	      TDATA_BYTES_C => 4,
74	      TDEST_BITS_C  => AXI_STREAM_CONFIG_G.TDEST_BITS_C,
75	      TID_BITS_C    => AXI_STREAM_CONFIG_G.TID_BITS_C,
76	      TKEEP_MODE_C  => TKEEP_COMP_C,
77	      TUSER_BITS_C  => 2,
78	      TUSER_MODE_C  => TUSER_FIRST_LAST_C);
79	
80	   type StateType is (
81	      IDLE_S,
82	      BLOWOFF_RX_S,
83	      BLOWOFF_READ_DATA_S,
84	      HDR_REQ_S,
85	      HDR_RESP_S,
86	      READ_S,
87	      WRITE_S,
88	      WAIT_ACK_S,
89	      FOOTER_S);
90	
91	   type RegType is record
92	      timer       : natural range 0 to TIMEOUT_C;
93	      hdrCnt      : slv(3 downto 0);
94	      remVer      : slv(7 downto 0);
95	      timeoutSize : slv(7 downto 0);
96	      timeoutCnt  : slv(7 downto 0);
97	      txnCnt      : slv(29 downto 0);
98	      memResp     : slv(7 downto 0);
99	      timeout     : sl;
100	      eofe        : sl;
101	      frameError  : sl;
102	      verMismatch : sl;
103	      reqError    : sl;
104	      rxSlave     : AxiStreamSlaveType;
105	      txMaster    : AxiStreamMasterType;
106	      state       : StateType;
107	      srpReq      : SrpV3ReqType;
108	      srpWrMaster : AxiStreamMasterType;
109	      srpRdSlave  : AxiStreamSlaveType;
110	   end record RegType;
111	   constant REG_INIT_C : RegType := (
112	      timer       => 0,
113	      hdrCnt      => (others => '0'),
114	      remVer      => (others => '0'),
115	      timeoutSize => (others => '0'),
116	      timeoutCnt  => (others => '0'),
117	      txnCnt      => (others => '0'),
118	      memResp     => (others => '0'),
119	      timeout     => '0',
120	      eofe        => '0',
121	      frameError  => '0',
122	      verMismatch => '0',
123	      reqError    => '0',
124	      rxSlave     => AXI_STREAM_SLAVE_INIT_C,
125	      txMaster    => axiStreamMasterInit(SRP_AXIS_CONFIG_C),
126	      state       => IDLE_S,
127	      srpReq      => SRPV3_REQ_INIT_C,
128	      srpWrMaster => axiStreamMasterInit(SRP_AXIS_CONFIG_C),
129	      srpRdSlave  => AXI_STREAM_SLAVE_INIT_C);
130	
131	   signal r   : RegType := REG_INIT_C;
132	   signal rin : RegType;
133	
134	   signal sCtrl          : AxiStreamCtrlType;
135	   signal rxMaster       : AxiStreamMasterType;
136	   signal rxSlave        : AxiStreamSlaveType;
137	   signal rxCtrl         : AxiStreamCtrlType;
138	   signal txSlave        : AxiStreamSlaveType;
139	   signal srpRdMasterInt : AxiStreamMasterType;
140	   signal srpRdSlaveInt  : AxiStreamSlaveType;
141	   signal srpWrMasterInt : AxiStreamMasterType;
142	   signal srpWrSlaveInt  : AxiStreamSlaveType;
143	
144	   -- attribute dont_touch                    : string;
145	   -- attribute dont_touch of r               : signal is "TRUE";
146	
147	begin
148	
149	   sAxisCtrl <= sCtrl;
150	
151	   RX_FIFO : entity surf.SsiFifo
152	      generic map (
153	         -- General Configurations
154	         TPD_G               => TPD_G,
155	         PIPE_STAGES_G       => PIPE_STAGES_G,
156	         SLAVE_READY_EN_G    => SLAVE_READY_EN_G,
157	         VALID_THOLD_G       => 0,      -- = 0 = only when frame ready
158	         -- FIFO configurations
159	         MEMORY_TYPE_G       => "block",
160	         GEN_SYNC_FIFO_G     => GEN_SYNC_FIFO_G,
161	         FIFO_ADDR_WIDTH_G   => 9,      -- 2kB/FIFO = 32-bits x 512 entries
162	         CASCADE_SIZE_G      => 3,      -- 6kB = 3 FIFOs x 2 kB/FIFO
163	         CASCADE_PAUSE_SEL_G => 2,      -- Set pause select on top FIFO
164	         FIFO_FIXED_THRESH_G => true,
165	         FIFO_PAUSE_THRESH_G => FIFO_PAUSE_THRESH_G,
166	         -- AXI Stream Port Configurations
167	         SLAVE_AXI_CONFIG_G  => AXI_STREAM_CONFIG_G,
168	         MASTER_AXI_CONFIG_G => SRP_AXIS_CONFIG_C)
169	      port map (
170	         -- Slave Port
171	         sAxisClk    => sAxisClk,
172	         sAxisRst    => sAxisRst,
173	         sAxisMaster => sAxisMaster,
174	         sAxisSlave  => sAxisSlave,
175	         sAxisCtrl   => sCtrl,
176	         -- Master Port
177	         mAxisClk    => srpClk,
178	         mAxisRst    => srpRst,
179	         mAxisMaster => rxMaster,
180	         mAxisSlave  => rxSlave);
181	
182	   GEN_SYNC_SLAVE : if (GEN_SYNC_FIFO_G = true) generate
183	      rxCtrl <= sCtrl;
184	   end generate;
185	
186	   GEN_ASYNC_SLAVE : if (GEN_SYNC_FIFO_G = false) generate
187	      Sync_Ctrl : entity surf.SynchronizerVector
188	         generic map (
189	            TPD_G   => TPD_G,
190	            WIDTH_G => 2,
191	            INIT_G  => "11")
192	         port map (
193	            clk        => srpClk,
194	            rst        => srpRst,
195	            dataIn(0)  => sCtrl.pause,
196	            dataIn(1)  => sCtrl.idle,
197	            dataOut(0) => rxCtrl.pause,
198	            dataOut(1) => rxCtrl.idle);
199	      Sync_Overflow : entity surf.SynchronizerOneShot
200	         generic map (
201	            TPD_G => TPD_G)
202	         port map (
203	            clk     => srpClk,
204	            rst     => srpRst,
205	            dataIn  => sCtrl.overflow,
206	            dataOut => rxCtrl.overflow);
207	   end generate;
208	
209	   comb : process (r, rxCtrl, rxMaster, srpAck, srpRdMasterInt, srpRst,
210	                   srpWrSlaveInt, txSlave) is
211	      variable v : RegType;
212	   begin
213	      -- Latch the current value
214	      v := r;
215	
216	      -- Set AxiStream defaults
217	      v.rxSlave := AXI_STREAM_SLAVE_INIT_C;
218	
219	      if txSlave.tReady = '1' then
220	         v.txMaster.tValid := '0';
221	         v.txMaster.tLast  := '0';
222	         v.txMaster.tUser  := (others => '0');
223	      end if;
224	
225	      v.srpRdSlave := AXI_STREAM_SLAVE_INIT_C;
226	
227	      if (srpWrSlaveInt.tReady = '1') then
228	         v.srpWrMaster.tValid := '0';
229	         v.txMaster.tLast     := '0';
230	         v.txMaster.tUser     := (others => '0');
231	      end if;
232	
233	      -- Timer is freerunning
234	      -- Reset to 0 when TIMEOUT_C reached
235	      if r.timer = TIMEOUT_C then
236	         v.timer := 0;
237	      else
238	         v.timer := r.timer + 1;
239	      end if;
240	
241	      -- State Machine
242	      case r.state is
243	         ----------------------------------------------------------------------
244	         when IDLE_S =>
245	            -- Reset error flags
246	            v.memResp     := (others => '0');
247	            -- v.timeout     := '0'; <--- if timeout ever happens then latch the timeout (don't reset) to inform SW that "hardware bus lock"
248	            v.eofe        := '0';
249	            v.frameError  := '0';
250	            v.verMismatch := '0';
251	            v.reqError    := '0';
252	
253	            -- Reset SRP request
254	            v.srpReq := SRPV3_REQ_INIT_C;
255	
256	            -- Reset other state registers
257	            v.timeoutSize := (others => '0');
258	            v.txnCnt      := (others => '0');
259	            v.hdrCnt      := (others => '0');
260	
261	            -- Check for overflow
262	            if rxCtrl.overflow = '1' then
263	               v.state := BLOWOFF_RX_S;
264	
265	            -- Check for extra read data (possibly from previous interrupted txn)
266	            elsif (srpRdMasterInt.tValid = '1') then
267	               v.state := BLOWOFF_READ_DATA_S;
268	
269	            -- Check for valid data
270	            elsif rxMaster.tValid = '1' then
271	               -- Check for SOF
272	               if (ssiGetUserSof(SRP_AXIS_CONFIG_C, rxMaster) = '1') then
273	                  -- Ok to start processing the header
274	                  v.state := HDR_REQ_S;
275	               else
276	                  -- Blowoff any RX data if no SOF
277	                  v.state := BLOWOFF_RX_S;
278	               end if;
279	            end if;
280	
281	         ----------------------------------------------------------------------
282	         when BLOWOFF_RX_S =>
283	            -- Dump rx data until tLast seen
284	            v.rxSlave.tReady := '1';
285	            if rxMaster.tValid = '1' and rxMaster.tLast = '1' then
286	               v.state := IDLE_S;
287	            end if;
288	
289	         ----------------------------------------------------------------------
290	         when BLOWOFF_READ_DATA_S =>
291	            -- Dump read data until tLast seen
292	            v.srpRdSlave.tReady := '1';
293	            if srpRdMasterInt.tValid = '1' and srpRdMasterInt.tLast = '1' then
294	               v.state := IDLE_S;
295	            end if;
296	
297	         ----------------------------------------------------------------------
298	         when HDR_REQ_S =>
299	            -- Check for valid data
300	            if rxMaster.tValid = '1' then
301	               -- Accept the data
302	               v.rxSlave.tReady := '1';
303	               -- Increment the header count
304	               v.hdrCnt := r.hdrCnt + 1;
305	
306	
307	               -- Check for tLast or EOFE
308	               if rxMaster.tLast = '1' then
309	                  -- Set the flags
310	                  v.frameError := '1';
311	                  v.hdrCnt     := (others => '0');
312	                  -- Next State
313	                  v.state      := HDR_RESP_S;
314	               end if;
315	
316	               -- Latch the request header fields based on which header word we're on
317	               case r.hdrCnt is
318	                  when X"0" =>
319	                     v.txMaster.tDest := rxMaster.tDest;
320	                     v.srpReq.remVer  := rxMaster.tData(7 downto 0);
321	                     v.srpReq.opCode  := rxMaster.tData(9 downto 8);
322	                     v.srpReq.spare   := rxMaster.tData(20 downto 10);
323	                     v.srpReq.prot    := rxMaster.tData(23 downto 21);
324	                     v.timeoutSize    := rxMaster.tData(31 downto 24);
325	                  when X"1" =>
326	                     v.srpReq.tid(31 downto 0) := rxMaster.tData(31 downto 0);
327	                  when X"2" =>
328	                     v.srpReq.addr(31 downto 0) := rxMaster.tData(31 downto 0);
329	                  when X"3" =>
330	                     v.srpReq.addr(63 downto 32) := rxMaster.tData(31 downto 0);
331	                  when X"4" =>
332	                     v.srpReq.reqSize(31 downto 0) := rxMaster.tData(31 downto 0);
333	
334	                     -- Reset frame error that might have been assigned above due to tLast
335	                     -- We expect tLast here
336	                     v.frameError := '0';
337	                     -- Check for no tLast
338	                     if (rxMaster.tLast = '0') then
339	                        -- Check for OP-codes that should have tLast
340	                        if (r.srpReq.opCode = SRP_NULL_C) or (r.srpReq.opCode = SRP_READ_C) then
341	                           -- Set the flags
342	                           v.frameError := '1';
343	                        end if;
344	                     else
345	                        -- Check for OP-codes that should NOT have tLast
346	                        if (r.srpReq.opCode = SRP_POSTED_WRITE_C) or (r.srpReq.opCode = SRP_WRITE_C) then
347	                           -- Set the flags
348	                           v.frameError := '1';
349	                        end if;
350	                     end if;
351	                     -- Next State
352	                     v.hdrCnt := (others => '0');
353	                     v.state  := HDR_RESP_S;
354	
355	                  when others => null;
356	               end case;
357	
358	            end if;
359	
360	         ----------------------------------------------------------------------
361	         when HDR_RESP_S =>
362	            -- Check if ready to move data
363	            if (v.txMaster.tValid = '0') then
364	               -- Check for posted write
365	               if r.srpReq.opCode /= SRP_POSTED_WRITE_C then
366	                  -- Set the flag
367	                  v.txMaster.tValid := '1';
368	               end if;
369	               -- Increment the counter
370	               v.hdrCnt := r.hdrCnt + 1;
371	               -- Check the counter
372	               case (r.hdrCnt) is
373	                  when x"0" =>
374	                     -- Set SOF
375	                     ssiSetUserSof(SRP_AXIS_CONFIG_C, v.txMaster, '1');
376	                     -- Set data bus
377	                     v.txMaster.tData(7 downto 0)   := SRP_VERSION_C;
378	                     v.txMaster.tData(9 downto 8)   := r.srpReq.opCode;
379	                     v.txMaster.tData(20 downto 10) := r.srpReq.spare;
380	                     v.txMaster.tData(23 downto 21) := r.srpReq.prot;
381	                     v.txMaster.tData(31 downto 24) := r.timeoutSize;
382	                  when x"1" =>
383	                     v.txMaster.tData(31 downto 0) := r.srpReq.tid(31 downto 0);
384	                  when x"2" =>
385	                     v.txMaster.tData(31 downto 0) := r.srpReq.addr(31 downto 0);
386	                  when x"3" =>
387	                     v.txMaster.tData(31 downto 0) := r.srpReq.addr(63 downto 32);
388	                  when others =>
389	                     v.txMaster.tData(31 downto 0) := r.srpReq.reqSize(31 downto 0);
390	                     -- Reset the counter
391	                     v.hdrCnt                      := x"0";
392	                     -- Check for NULL
393	                     if r.srpReq.opCode = SRP_NULL_C then
394	                        -- Next State
395	                        v.state := FOOTER_S;
396	                     end if;
397	
398	                     -- Check for framing error or EOFE or timeout (A.K.A. "hardware bus lock")
399	                     if (r.frameError = '1') or (r.eofe = '1') or (r.timeout = '1') then
400	                        -- Next State
401	                        v.state := FOOTER_S;
402	                     end if;
403	                     -- Check for version mismatch
404	                     if r.srpReq.remVer /= SRP_VERSION_C then
405	                        -- Set the flags
406	                        v.verMismatch := '1';
407	                        -- Next State
408	                        v.state       := FOOTER_S;
409	                     end if;
410	                     -- Check for invalid reqSize with respect to writes
411	                     if ((r.srpReq.opCode = SRP_WRITE_C) or (r.srpReq.opCode = SRP_POSTED_WRITE_C)) and
412	                        (r.srpReq.reqSize(31 downto 12) /= 0) then
413	                        -- Set the flags
414	                        v.reqError := '1';
415	                        -- Next State
416	                        v.state    := FOOTER_S;
417	                     end if;
418	
419	                     -- Need to double check all the cases here
420	                     -- Check for non 32-bit transaction request
421	                     if (r.srpReq.opCode /= SRP_NULL_C) then
422	                        if BYTE_ACCESS_G = false and r.srpReq.reqSize(1 downto 0) /= "11" then
423	                           v.reqError := '1';
424	                           v.state    := FOOTER_S;
425	                        end if;
426	
427	                        -- Check for non 32-bit address alignment
428	                        if BYTE_ACCESS_G = false and UNALIGNED_ACCESS_G = false and r.srpReq.addr(1 downto 0) /= 0 then
429	                           v.reqError := '1';
430	                           v.state    := FOOTER_S;
431	                        end if;
432	
433	                        -- Check that request op is enabled
434	                        if (READ_EN_G = false and r.srpReq.opCode = SRP_READ_C) then
435	                           v.reqError := '1';
436	                           v.state    := FOOTER_S;
437	                        end if;
438	
439	                        if (WRITE_EN_G = false and (r.srpReq.opCode = SRP_WRITE_C or r.srpReq.opCode = SRP_POSTED_WRITE_C)) then
440	                           v.reqError := '1';
441	                           v.state    := FOOTER_S;
442	                        end if;
443	                     end if;
444	
445	                     -------------------------------------------------------------------------------
446	
447	                     -- If no error found above, proceed with read or write request
448	                     if (v.state /= FOOTER_S) then
449	                        -- Issue an SRP request
450	                        v.srpReq.request := '1';
451	
452	                        -- Reset the timer
453	                        v.timer      := 0;
454	                        v.timeoutCnt := (others => '0');
455	
456	                        -- Check for read
457	                        if r.srpReq.opCode = SRP_READ_C then
458	                           v.state := READ_S;
459	
460	                        -- Check for write
461	                        elsif (r.srpReq.opCode = SRP_WRITE_C or r.srpReq.opCode = SRP_POSTED_WRITE_C) then
462	                           v.state := WRITE_S;
463	
464	                        else
465	                           -- Redundant null check but more opcodes could be added later
466	                           v.state := FOOTER_S;
467	                        end if;
468	                     end if;
469	               end case;
470	            end if;
471	
472	
473	         ----------------------------------------------------------------------
474	         when READ_S =>
475	            -- Send read data through to txMaster
476	            if (srpRdMasterInt.tValid = '1' and v.txMaster.tValid = '0') then
477	               v.srpRdSlave.tReady := '1';
478	               v.txMaster.tValid   := '1';
479	
480	               -- Zero out data segments where tkeep not set
481	               -- There must be a more elegant way to do this
482	               for i in 3 downto 0 loop
483	                  if (srpRdMasterInt.tKeep(i) = '1') then
484	                     v.txMaster.tData((i+1)*8-1 downto i*8) := srpRdMasterInt.tData((i+1)*8-1 downto i*8);
485	                  else
486	                     v.txMaster.tData((i+1)*8-1 downto i*8) := (others => '0');
487	                  end if;
488	               end loop;
489	
490	
491	               -- Count each txn
492	               -- If tLast before cntSize, eofe
493	               -- if cntSize reached and no tlast, bleed read data, eofe
494	               v.txnCnt := r.txnCnt + 1;
495	               if r.txnCnt = r.srpReq.reqSize(31 downto 2) and srpRdMasterInt.tLast = '1' then
496	                  -- Done when reqSize and tlast
497	                  v.state := WAIT_ACK_S;
498	               elsif (srpRdMasterInt.tLast = '1') then
499	                  -- tLast too early
500	                  v.state := WAIT_ACK_S;
501	                  v.eofe  := '1';       -- Should assign a memResp bit
502	               elsif (r.txnCnt = r.srpReq.reqSize(31 downto 2)) then
503	                  -- No tLast when expected
504	                  v.state := FOOTER_S;
505	                  v.eofe  := '1';       -- Should assign a memResp bit
506	               end if;
507	            end if;
508	
509	            -- Some downstream implementations can reject a read immediately
510	            -- without producing any read-data beats. In that case the request
511	            -- still needs to complete through the ack/footer path.
512	            if (srpAck.done = '1' and srpRdMasterInt.tValid = '0' and r.txnCnt = 0 and srpAck.respCode /= 0) then
513	               v.state := WAIT_ACK_S;
514	            end if;
515	
516	
517	            -- Check if timer enabled
518	            if r.timeoutSize /= 0 then
519	               -- Check 100 ms timer
520	               if r.timer = TIMEOUT_C then
521	                  -- Increment counter
522	                  v.timeoutCnt := r.timeoutCnt + 1;
523	                  -- Check the counter
524	                  if v.timeoutCnt = r.timeoutSize then
525	                     -- Set the flags
526	                     v.timeout := '1';
527	                     -- Next State
528	                     v.state   := FOOTER_S;
529	                  end if;
530	               end if;
531	            end if;
532	
533	         ----------------------------------------------------------------------
534	         when WRITE_S =>
535	            -- Check for valid data and both tx and srpWr ready
536	            if (rxMaster.tValid = '1') and (v.txMaster.tValid = '0') and (v.srpWrMaster.tValid = '0')then
537	               -- Accept the data
538	               v.rxSlave.tReady := '1';
539	
540	               -- Echo the write data back, but not if posted write
541	               v.txMaster.tValid             := toSl(r.srpReq.opCode /= SRP_POSTED_WRITE_C);
542	               v.txMaster.tData(31 downto 0) := rxMaster.tData(31 downto 0);
543	
544	               -- Set the write data bus
545	               v.srpWrMaster.tValid             := '1';
546	               v.srpWrMaster.tData(31 downto 0) := rxMaster.tData(31 downto 0);
547	               v.srpWrMaster.tLast              := rxMaster.tLast;
548	
549	               -- Set tkeep for last data word as it may not be a full word
550	               if (rxMaster.tLast = '1') then
551	                  v.srpWrMaster.tKeep := genTKeep(conv_integer(r.srpReq.reqSize(1 downto 0))+1);
552	               else
553	                  v.srpWrMaster.tKeep := genTKeep(4);
554	               end if;
555	
556	               -- Count each txn
557	               -- If tLast before cntSize, frameError
558	               -- if cntSize reached and no tlast, bleed write data, frame error
559	               v.txnCnt := r.txnCnt + 1;
560	               if r.txnCnt = r.srpReq.reqSize(31 downto 2) and rxMaster.tLast = '1' then
561	                  -- Done when reqSize reached and tlast
562	                  v.state := WAIT_ACK_S;
563	               elsif (r.txnCnt = r.srpReq.reqSize(31 downto 2) or rxMaster.tLast = '1') then
564	                  -- tLast too early or too late
565	                  -- Extra rxData will get blown off once IDLE_S state is reached
566	                  -- Due to missing SOF
567	                  v.state      := WAIT_ACK_S;
568	                  v.frameError := '1';
569	               end if;
570	            end if;
571	
572	
573	            -- Check if timer enabled
574	            if r.timeoutSize /= 0 then
575	               -- Check 100 ms timer
576	               if r.timer = TIMEOUT_C then
577	                  -- Increment counter
578	                  v.timeoutCnt := r.timeoutCnt + 1;
579	                  -- Check the counter
580	                  if v.timeoutCnt = r.timeoutSize then
581	                     -- Set the flags
582	                     v.timeout := '1';
583	                     -- Next State
584	                     v.state   := FOOTER_S;
585	                  end if;
586	               end if;
587	            end if;
588	
589	
590	         ----------------------------------------------------------------------
591	         when WAIT_ACK_S =>
592	            -- Wait for final ack from downstream
593	            if (srpAck.done = '1') then
594	               v.srpReq.request := '0';
595	               v.memResp        := srpAck.respCode;
596	            end if;
597	
598	            -- Wait until both request and ack.done release before proceeding to footer
599	            if (r.srpReq.request = '0' and srpAck.done = '0') then
600	               v.state := FOOTER_S;
601	            end if;
602	
603	            -- Check if timer enabled
604	            if r.timeoutSize /= 0 then
605	               -- Check 100 ms timer
606	               if r.timer = TIMEOUT_C then
607	                  -- Increment counter
608	                  v.timeoutCnt := r.timeoutCnt + 1;
609	                  -- Check the counter
610	                  if v.timeoutCnt = r.timeoutSize then
611	                     -- Set the flags
612	                     v.timeout := '1';
613	                     -- Next State
614	                     v.state   := FOOTER_S;
615	                  end if;
616	               end if;
617	            end if;
618	
619	         ----------------------------------------------------------------------
620	         when FOOTER_S =>
621	            -- Might have arrived here after timeout with request still pending
622	            -- Release them now
623	            v.srpReq.request := '0';
624	
625	            -- Check if ready to move data
626	            if (v.txMaster.tValid = '0') then
627	               -- Check for posted write
628	               if r.srpReq.opCode /= SRP_POSTED_WRITE_C then
629	                  -- Set the flags
630	                  v.txMaster.tValid := '1';
631	               end if;
632	               -- Set the footer data
633	               v.txMaster.tLast               := '1';
634	               v.txMaster.tData(7 downto 0)   := r.memResp;
635	               v.txMaster.tData(8)            := r.timeout;
636	               v.txMaster.tData(9)            := r.eofe;
637	               v.txMaster.tData(10)           := r.frameError;
638	               v.txMaster.tData(11)           := r.verMismatch;
639	               v.txMaster.tData(12)           := r.reqError;
640	               v.txMaster.tData(13)           := r.timeout;
641	               v.txMaster.tData(31 downto 14) := (others => '0');
642	               -- Next state
643	               v.state                        := IDLE_S;
644	            end if;
645	
646	      end case;
647	
648	      -- Update the EOFE flag
649	      if (rxMaster.tLast = '1') and (v.rxSlave.tReady = '1') then
650	         v.eofe := ssiGetUserEofe(SRP_AXIS_CONFIG_C, rxMaster);
651	      end if;
652	
653	      -- Combinatorial outputs before the reset
654	      rxSlave       <= v.rxSlave;
655	      srpRdSlaveInt <= v.srpRdSlave;
656	
657	      -- Reset
658	      if (srpRst = '1') then
659	         v := REG_INIT_C;
660	      end if;
661	
662	      -- Register the variable for next clock cycle
663	      rin <= v;
664	
665	      -- Registered Outputs
666	      srpReq         <= r.srpReq;
667	      srpWrMasterInt <= r.srpWrMaster;
668	
669	   end process comb;
670	
671	   seq : process (srpClk) is
672	   begin
673	      if (rising_edge(srpClk)) then
674	         r <= rin after TPD_G;
675	      end if;
676	   end process seq;
677	
678	   TX_FIFO : entity surf.AxiStreamFifoV2
679	      generic map (
680	         -- General Configurations
681	         TPD_G               => TPD_G,
682	         PIPE_STAGES_G       => PIPE_STAGES_G,
683	         SLAVE_READY_EN_G    => true,
684	         VALID_THOLD_G       => TX_VALID_THOLD_G,
685	         -- FIFO configurations
686	         SYNTH_MODE_G        => SYNTH_MODE_G,
687	         MEMORY_TYPE_G       => "block",
688	         GEN_SYNC_FIFO_G     => GEN_SYNC_FIFO_G,
689	         CASCADE_SIZE_G      => 1,
690	         FIFO_ADDR_WIDTH_G   => 9,
691	         -- AXI Stream Port Configurations
692	         SLAVE_AXI_CONFIG_G  => SRP_AXIS_CONFIG_C,
693	         MASTER_AXI_CONFIG_G => AXI_STREAM_CONFIG_G)
694	      port map (
695	         -- Slave Port
696	         sAxisClk    => srpClk,
697	         sAxisRst    => srpRst,
698	         sAxisMaster => r.txMaster,
699	         sAxisSlave  => txSlave,
700	         -- Master Port
701	         mAxisClk    => mAxisClk,
702	         mAxisRst    => mAxisRst,
703	         mAxisMaster => mAxisMaster,
704	         mAxisSlave  => mAxisSlave);
705	
706	   U_Rx : entity surf.AxiStreamResize
707	      generic map (
708	         TPD_G               => TPD_G,
709	         SLAVE_AXI_CONFIG_G  => AXI_STREAM_CONFIG_G,
710	         MASTER_AXI_CONFIG_G => SRP_AXIS_CONFIG_C)
711	      port map (
712	         -- Clock and reset
713	         axisClk     => srpClk,
714	         axisRst     => srpRst,
715	         -- Slave Port
716	         sAxisMaster => srpRdMaster,
717	         sAxisSlave  => srpRdSlave,
718	         -- Master Port
719	         mAxisMaster => srpRdMasterInt,
720	         mAxisSlave  => srpRdSlaveInt);
721	
722	   U_Tx : entity surf.AxiStreamResize
723	      generic map (
724	         TPD_G               => TPD_G,
725	         SLAVE_AXI_CONFIG_G  => SRP_AXIS_CONFIG_C,
726	         MASTER_AXI_CONFIG_G => AXI_STREAM_CONFIG_G)
727	      port map (
728	         -- Clock and reset
729	         axisClk     => srpClk,
730	         axisRst     => srpRst,
731	         -- Slave Port
732	         sAxisMaster => srpWrMasterInt,
733	         sAxisSlave  => srpWrSlaveInt,
734	         -- Master Port
735	         mAxisMaster => srpWrMaster,
736	         mAxisSlave  => srpWrSlave);
737	
738	end rtl;
739

file.content:
-------------------------------------------------------------------------------
-- Title      : SRPv3 Protocol: https://confluence.slac.stanford.edu/x/cRmVD
-------------------------------------------------------------------------------
-- Company    : SLAC National Accelerator Laboratory
-------------------------------------------------------------------------------
-- Description: SLAC Register Protocol Version 3, Core FSM Logic
-------------------------------------------------------------------------------
-- This file is part of 'SLAC Firmware Standard Library'.
-- It is subject to the license terms in the LICENSE.txt file found in the
-- top-level directory of this distribution and at:
--    https://confluence.slac.stanford.edu/display/ppareg/LICENSE.html.
-- No part of 'SLAC Firmware Standard Library', including this file,
-- may be copied, modified, propagated, or distributed except according to
-- the terms contained in the LICENSE.txt file.
-------------------------------------------------------------------------------

library ieee;
use ieee.std_logic_1164.all;
use ieee.std_logic_arith.all;
use ieee.std_logic_unsigned.all;

library surf;
use surf.StdRtlPkg.all;
use surf.AxiStreamPkg.all;
use surf.SsiPkg.all;
use surf.AxiLitePkg.all;
use surf.SrpV3Pkg.all;

entity SrpV3Core is
   generic (
      TPD_G               : time                    := 1 ns;
      PIPE_STAGES_G       : natural range 0 to 16   := 1;
      SYNTH_MODE_G        : string                  := "inferred";
      FIFO_PAUSE_THRESH_G : positive range 1 to 511 := 256;
      TX_VALID_THOLD_G    : positive                := 1;
      SLAVE_READY_EN_G    : boolean                 := false;
      GEN_SYNC_FIFO_G     : boolean                 := false;
      SRP_CLK_FREQ_G      : real                    := 156.25E+6;  -- units of Hz
      AXI_STREAM_CONFIG_G : AxiStreamConfigType;
      UNALIGNED_ACCESS_G  : boolean                 := false;
      BYTE_ACCESS_G       : boolean                 := false;
      WRITE_EN_G          : boolean                 := true;  -- Write ops enabled
      READ_EN_G           : boolean                 := true);  -- Read ops enabled
   port (
      -- AXIS Slave Interface (sAxisClk domain)
      sAxisClk    : in  sl;
      sAxisRst    : in  sl;
      sAxisMaster : in  AxiStreamMasterType;
      sAxisSlave  : out AxiStreamSlaveType;
      sAxisCtrl   : out AxiStreamCtrlType;
      -- AXIS Master Interface (mAxisClk domain)
      mAxisClk    : in  sl;
      mAxisRst    : in  sl;
      mAxisMaster : out AxiStreamMasterType;
      mAxisSlave  : in  AxiStreamSlaveType;
      -- Master AXI-Lite Interface (axilClk domain)
      srpClk      : in  sl;
      srpRst      : in  sl;
      srpReq      : out SrpV3ReqType;
      srpAck      : in  SrpV3AckType;
      srpWrMaster : out AxiStreamMasterType;
      srpWrSlave  : in  AxiStreamSlaveType;
      srpRdMaster : in  AxiStreamMasterType;
      srpRdSlave  : out AxiStreamSlaveType);
end SrpV3Core;

architecture rtl of SrpV3Core is

   constant TIMEOUT_C : natural := (getTimeRatio(SRP_CLK_FREQ_G, 10.0) - 1);  -- 100 ms timeout

   constant SRP_AXIS_CONFIG_C : AxiStreamConfigType := (
      TSTRB_EN_C    => false,
      TDATA_BYTES_C => 4,
      TDEST_BITS_C  => AXI_STREAM_CONFIG_G.TDEST_BITS_C,
      TID_BITS_C    => AXI_STREAM_CONFIG_G.TID_BITS_C,
      TKEEP_MODE_C  => TKEEP_COMP_C,
      TUSER_BITS_C  => 2,
      TUSER_MODE_C  => TUSER_FIRST_LAST_C);

   type StateType is (
      IDLE_S,
      BLOWOFF_RX_S,
      BLOWOFF_READ_DATA_S,
      HDR_REQ_S,
      HDR_RESP_S,
      READ_S,
      WRITE_S,
      WAIT_ACK_S,
      FOOTER_S);

   type RegType is record
      timer       : natural range 0 to TIMEOUT_C;
      hdrCnt      : slv(3 downto 0);
      remVer      : slv(7 downto 0);
      timeoutSize : slv(7 downto 0);
      timeoutCnt  : slv(7 downto 0);
      txnCnt      : slv(29 downto 0);
      memResp     : slv(7 downto 0);
      timeout     : sl;
      eofe        : sl;
      frameError  : sl;
      verMismatch : sl;
      reqError    : sl;
      rxSlave     : AxiStreamSlaveType;
      txMaster    : AxiStreamMasterType;
      state       : StateType;
      srpReq      : SrpV3ReqType;
      srpWrMaster : AxiStreamMasterType;
      srpRdSlave  : AxiStreamSlaveType;
   end record RegType;
   constant REG_INIT_C : RegType := (
      timer       => 0,
      hdrCnt      => (others => '0'),
      remVer      => (others => '0'),
      timeoutSize => (others => '0'),
      timeoutCnt  => (others => '0'),
      txnCnt      => (others => '0'),
      memResp     => (others => '0'),
      timeout     => '0',
      eofe        => '0',
      frameError  => '0',
      verMismatch => '0',
      reqError    => '0',
      rxSlave     => AXI_STREAM_SLAVE_INIT_C,
      txMaster    => axiStreamMasterInit(SRP_AXIS_CONFIG_C),
      state       => IDLE_S,
      srpReq      => SRPV3_REQ_INIT_C,
      srpWrMaster => axiStreamMasterInit(SRP_AXIS_CONFIG_C),
      srpRdSlave  => AXI_STREAM_SLAVE_INIT_C);

   signal r   : RegType := REG_INIT_C;
   signal rin : RegType;

   signal sCtrl          : AxiStreamCtrlType;
   signal rxMaster       : AxiStreamMasterType;
   signal rxSlave        : AxiStreamSlaveType;
   signal rxCtrl         : AxiStreamCtrlType;
   signal txSlave        : AxiStreamSlaveType;
   signal srpRdMasterInt : AxiStreamMasterType;
   signal srpRdSlaveInt  : AxiStreamSlaveType;
   signal srpWrMasterInt : AxiStreamMasterType;
   signal srpWrSlaveInt  : AxiStreamSlaveType;

   -- attribute dont_touch                    : string;
   -- attribute dont_touch of r               : signal is "TRUE";

begin

   sAxisCtrl <= sCtrl;

   RX_FIFO : entity surf.SsiFifo
      generic map (
         -- General Configurations
         TPD_G               => TPD_G,
         PIPE_STAGES_G       => PIPE_STAGES_G,
         SLAVE_READY_EN_G    => SLAVE_READY_EN_G,
         VALID_THOLD_G       => 0,      -- = 0 = only when frame ready
         -- FIFO configurations
         MEMORY_TYPE_G       => "block",
         GEN_SYNC_FIFO_G     => GEN_SYNC_FIFO_G,
         FIFO_ADDR_WIDTH_G   => 9,      -- 2kB/FIFO = 32-bits x 512 entries
         CASCADE_SIZE_G      => 3,      -- 6kB = 3 FIFOs x 2 kB/FIFO
         CASCADE_PAUSE_SEL_G => 2,      -- Set pause select on top FIFO
         FIFO_FIXED_THRESH_G => true,
         FIFO_PAUSE_THRESH_G => FIFO_PAUSE_THRESH_G,
         -- AXI Stream Port Configurations
         SLAVE_AXI_CONFIG_G  => AXI_STREAM_CONFIG_G,
         MASTER_AXI_CONFIG_G => SRP_AXIS_CONFIG_C)
      port map (
         -- Slave Port
         sAxisClk    => sAxisClk,
         sAxisRst    => sAxisRst,
         sAxisMaster => sAxisMaster,
         sAxisSlave  => sAxisSlave,
         sAxisCtrl   => sCtrl,
         -- Master Port
         mAxisClk    => srpClk,
         mAxisRst    => srpRst,
         mAxisMaster => rxMaster,
         mAxisSlave  => rxSlave);

   GEN_SYNC_SLAVE : if (GEN_SYNC_FIFO_G = true) generate
      rxCtrl <= sCtrl;
   end generate;

   GEN_ASYNC_SLAVE : if (GEN_SYNC_FIFO_G = false) generate
      Sync_Ctrl : entity surf.SynchronizerVector
         generic map (
            TPD_G   => TPD_G,
            WIDTH_G => 2,
            INIT_G  => "11")
         port map (
            clk        => srpClk,
            rst        => srpRst,
            dataIn(0)  => sCtrl.pause,
            dataIn(1)  => sCtrl.idle,
            dataOut(0) => rxCtrl.pause,
            dataOut(1) => rxCtrl.idle);
      Sync_Overflow : entity surf.SynchronizerOneShot
         generic map (
            TPD_G => TPD_G)
         port map (
            clk     => srpClk,
            rst     => srpRst,
            dataIn  => sCtrl.overflow,
            dataOut => rxCtrl.overflow);
   end generate;

   comb : process (r, rxCtrl, rxMaster, srpAck, srpRdMasterInt, srpRst,
                   srpWrSlaveInt, txSlave) is
      variable v : RegType;
   begin
      -- Latch the current value
      v := r;

      -- Set AxiStream defaults
      v.rxSlave := AXI_STREAM_SLAVE_INIT_C;

      if txSlave.tReady = '1' then
         v.txMaster.tValid := '0';
         v.txMaster.tLast  := '0';
         v.txMaster.tUser  := (others => '0');
      end if;

      v.srpRdSlave := AXI_STREAM_SLAVE_INIT_C;

      if (srpWrSlaveInt.tReady = '1') then
         v.srpWrMaster.tValid := '0';
         v.txMaster.tLast     := '0';
         v.txMaster.tUser     := (others => '0');
      end if;

      -- Timer is freerunning
      -- Reset to 0 when TIMEOUT_C reached
      if r.timer = TIMEOUT_C then
         v.timer := 0;
      else
         v.timer := r.timer + 1;
      end if;

      -- State Machine
      case r.state is
         ----------------------------------------------------------------------
         when IDLE_S =>
            -- Reset error flags
            v.memResp     := (others => '0');
            -- v.timeout     := '0'; <--- if timeout ever happens then latch the timeout (don't reset) to inform SW that "hardware bus lock"
            v.eofe        := '0';
            v.frameError  := '0';
            v.verMismatch := '0';
            v.reqError    := '0';

            -- Reset SRP request
            v.srpReq := SRPV3_REQ_INIT_C;

            -- Reset other state registers
            v.timeoutSize := (others => '0');
            v.txnCnt      := (others => '0');
            v.hdrCnt      := (others => '0');

            -- Check for overflow
            if rxCtrl.overflow = '1' then
               v.state := BLOWOFF_RX_S;

            -- Check for extra read data (possibly from previous interrupted txn)
            elsif (srpRdMasterInt.tValid = '1') then
               v.state := BLOWOFF_READ_DATA_S;

            -- Check for valid data
            elsif rxMaster.tValid = '1' then
               -- Check for SOF
               if (ssiGetUserSof(SRP_AXIS_CONFIG_C, rxMaster) = '1') then
                  -- Ok to start processing the header
                  v.state := HDR_REQ_S;
               else
                  -- Blowoff any RX data if no SOF
                  v.state := BLOWOFF_RX_S;
               end if;
            end if;

         ----------------------------------------------------------------------
         when BLOWOFF_RX_S =>
            -- Dump rx data until tLast seen
            v.rxSlave.tReady := '1';
            if rxMaster.tValid = '1' and rxMaster.tLast = '1' then
               v.state := IDLE_S;
            end if;

         ----------------------------------------------------------------------
         when BLOWOFF_READ_DATA_S =>
            -- Dump read data until tLast seen
            v.srpRdSlave.tReady := '1';
            if srpRdMasterInt.tValid = '1' and srpRdMasterInt.tLast = '1' then
               v.state := IDLE_S;
            end if;

         ----------------------------------------------------------------------
         when HDR_REQ_S =>
            -- Check for valid data
            if rxMaster.tValid = '1' then
               -- Accept the data
               v.rxSlave.tReady := '1';
               -- Increment the header count
               v.hdrCnt := r.hdrCnt + 1;


               -- Check for tLast or EOFE
               if rxMaster.tLast = '1' then
                  -- Set the flags
                  v.frameError := '1';
                  v.hdrCnt     := (others => '0');
                  -- Next State
                  v.state      := HDR_RESP_S;
               end if;

               -- Latch the request header fields based on which header word we're on
               case r.hdrCnt is
                  when X"0" =>
                     v.txMaster.tDest := rxMaster.tDest;
                     v.srpReq.remVer  := rxMaster.tData(7 downto 0);
                     v.srpReq.opCode  := rxMaster.tData(9 downto 8);
                     v.srpReq.spare   := rxMaster.tData(20 downto 10);
                     v.srpReq.prot    := rxMaster.tData(23 downto 21);
                     v.timeoutSize    := rxMaster.tData(31 downto 24);
                  when X"1" =>
                     v.srpReq.tid(31 downto 0) := rxMaster.tData(31 downto 0);
                  when X"2" =>
                     v.srpReq.addr(31 downto 0) := rxMaster.tData(31 downto 0);
                  when X"3" =>
                     v.srpReq.addr(63 downto 32) := rxMaster.tData(31 downto 0);
                  when X"4" =>
                     v.srpReq.reqSize(31 downto 0) := rxMaster.tData(31 downto 0);

                     -- Reset frame error that might have been assigned above due to tLast
                     -- We expect tLast here
                     v.frameError := '0';
                     -- Check for no tLast
                     if (rxMaster.tLast = '0') then
                        -- Check for OP-codes that should have tLast
                        if (r.srpReq.opCode = SRP_NULL_C) or (r.srpReq.opCode = SRP_READ_C) then
                           -- Set the flags
                           v.frameError := '1';
                        end if;
                     else
                        -- Check for OP-codes that should NOT have tLast
                        if (r.srpReq.opCode = SRP_POSTED_WRITE_C) or (r.srpReq.opCode = SRP_WRITE_C) then
                           -- Set the flags
                           v.frameError := '1';
                        end if;
                     end if;
                     -- Next State
                     v.hdrCnt := (others => '0');
                     v.state  := HDR_RESP_S;

                  when others => null;
               end case;

            end if;

         ----------------------------------------------------------------------
         when HDR_RESP_S =>
            -- Check if ready to move data
            if (v.txMaster.tValid = '0') then
               -- Check for posted write
               if r.srpReq.opCode /= SRP_POSTED_WRITE_C then
                  -- Set the flag
                  v.txMaster.tValid := '1';
               end if;
               -- Increment the counter
               v.hdrCnt := r.hdrCnt + 1;
               -- Check the counter
               case (r.hdrCnt) is
                  when x"0" =>
                     -- Set SOF
                     ssiSetUserSof(SRP_AXIS_CONFIG_C, v.txMaster, '1');
                     -- Set data bus
                     v.txMaster.tData(7 downto 0)   := SRP_VERSION_C;
                     v.txMaster.tData(9 downto 8)   := r.srpReq.opCode;
                     v.txMaster.tData(20 downto 10) := r.srpReq.spare;
                     v.txMaster.tData(23 downto 21) := r.srpReq.prot;
                     v.txMaster.tData(31 downto 24) := r.timeoutSize;
                  when x"1" =>
                     v.txMaster.tData(31 downto 0) := r.srpReq.tid(31 downto 0);
                  when x"2" =>
                     v.txMaster.tData(31 downto 0) := r.srpReq.addr(31 downto 0);
                  when x"3" =>
                     v.txMaster.tData(31 downto 0) := r.srpReq.addr(63 downto 32);
                  when others =>
                     v.txMaster.tData(31 downto 0) := r.srpReq.reqSize(31 downto 0);
                     -- Reset the counter
                     v.hdrCnt                      := x"0";
                     -- Check for NULL
                     if r.srpReq.opCode = SRP_NULL_C then
                        -- Next State
                        v.state := FOOTER_S;
                     end if;

                     -- Check for framing error or EOFE or timeout (A.K.A. "hardware bus lock")
                     if (r.frameError = '1') or (r.eofe = '1') or (r.timeout = '1') then
                        -- Next State
                        v.state := FOOTER_S;
                     end if;
                     -- Check for version mismatch
                     if r.srpReq.remVer /= SRP_VERSION_C then
                        -- Set the flags
                        v.verMismatch := '1';
                        -- Next State
                        v.state       := FOOTER_S;
                     end if;
                     -- Check for invalid reqSize with respect to writes
                     if ((r.srpReq.opCode = SRP_WRITE_C) or (r.srpReq.opCode = SRP_POSTED_WRITE_C)) and
                        (r.srpReq.reqSize(31 downto 12) /= 0) then
                        -- Set the flags
                        v.reqError := '1';
                        -- Next State
                        v.state    := FOOTER_S;
                     end if;

                     -- Need to double check all the cases here
                     -- Check for non 32-bit transaction request
                     if (r.srpReq.opCode /= SRP_NULL_C) then
                        if BYTE_ACCESS_G = false and r.srpReq.reqSize(1 downto 0) /= "11" then
                           v.reqError := '1';
                           v.state    := FOOTER_S;
                        end if;

                        -- Check for non 32-bit address alignment
                        if BYTE_ACCESS_G = false and UNALIGNED_ACCESS_G = false and r.srpReq.addr(1 downto 0) /= 0 then
                           v.reqError := '1';
                           v.state    := FOOTER_S;
                        end if;

                        -- Check that request op is enabled
                        if (READ_EN_G = false and r.srpReq.opCode = SRP_READ_C) then
                           v.reqError := '1';
                           v.state    := FOOTER_S;
                        end if;

                        if (WRITE_EN_G = false and (r.srpReq.opCode = SRP_WRITE_C or r.srpReq.opCode = SRP_POSTED_WRITE_C)) then
                           v.reqError := '1';
                           v.state    := FOOTER_S;
                        end if;
                     end if;

                     -------------------------------------------------------------------------------

                     -- If no error found above, proceed with read or write request
                     if (v.state /= FOOTER_S) then
                        -- Issue an SRP request
                        v.srpReq.request := '1';

                        -- Reset the timer
                        v.timer      := 0;
                        v.timeoutCnt := (others => '0');

                        -- Check for read
                        if r.srpReq.opCode = SRP_READ_C then
                           v.state := READ_S;

                        -- Check for write
                        elsif (r.srpReq.opCode = SRP_WRITE_C or r.srpReq.opCode = SRP_POSTED_WRITE_C) then
                           v.state := WRITE_S;

                        else
                           -- Redundant null check but more opcodes could be added later
                           v.state := FOOTER_S;
                        end if;
                     end if;
               end case;
            end if;


         ----------------------------------------------------------------------
         when READ_S =>
            -- Send read data through to txMaster
            if (srpRdMasterInt.tValid = '1' and v.txMaster.tValid = '0') then
               v.srpRdSlave.tReady := '1';
               v.txMaster.tValid   := '1';

               -- Zero out data segments where tkeep not set
               -- There must be a more elegant way to do this
               for i in 3 downto 0 loop
                  if (srpRdMasterInt.tKeep(i) = '1') then
                     v.txMaster.tData((i+1)*8-1 downto i*8) := srpRdMasterInt.tData((i+1)*8-1 downto i*8);
                  else
                     v.txMaster.tData((i+1)*8-1 downto i*8) := (others => '0');
                  end if;
               end loop;


               -- Count each txn
               -- If tLast before cntSize, eofe
               -- if cntSize reached and no tlast, bleed read data, eofe
               v.txnCnt := r.txnCnt + 1;
               if r.txnCnt = r.srpReq.reqSize(31 downto 2) and srpRdMasterInt.tLast = '1' then
                  -- Done when reqSize and tlast
                  v.state := WAIT_ACK_S;
               elsif (srpRdMasterInt.tLast = '1') then
                  -- tLast too early
                  v.state := WAIT_ACK_S;
                  v.eofe  := '1';       -- Should assign a memResp bit
               elsif (r.txnCnt = r.srpReq.reqSize(31 downto 2)) then
                  -- No tLast when expected
                  v.state := FOOTER_S;
                  v.eofe  := '1';       -- Should assign a memResp bit
               end if;
            end if;

            -- Some downstream implementations can reject a read immediately
            -- without producing any read-data beats. In that case the request
            -- still needs to complete through the ack/footer path.
            if (srpAck.done = '1' and srpRdMasterInt.tValid = '0' and r.txnCnt = 0 and srpAck.respCode /= 0) then
               v.state := WAIT_ACK_S;
            end if;


            -- Check if timer enabled
            if r.timeoutSize /= 0 then
               -- Check 100 ms timer
               if r.timer = TIMEOUT_C then
                  -- Increment counter
                  v.timeoutCnt := r.timeoutCnt + 1;
                  -- Check the counter
                  if v.timeoutCnt = r.timeoutSize then
                     -- Set the flags
                     v.timeout := '1';
                     -- Next State
                     v.state   := FOOTER_S;
                  end if;
               end if;
            end if;

         ----------------------------------------------------------------------
         when WRITE_S =>
            -- Check for valid data and both tx and srpWr ready
            if (rxMaster.tValid = '1') and (v.txMaster.tValid = '0') and (v.srpWrMaster.tValid = '0')then
               -- Accept the data
               v.rxSlave.tReady := '1';

               -- Echo the write data back, but not if posted write
               v.txMaster.tValid             := toSl(r.srpReq.opCode /= SRP_POSTED_WRITE_C);
               v.txMaster.tData(31 downto 0) := rxMaster.tData(31 downto 0);

               -- Set the write data bus
               v.srpWrMaster.tValid             := '1';
               v.srpWrMaster.tData(31 downto 0) := rxMaster.tData(31 downto 0);
               v.srpWrMaster.tLast              := rxMaster.tLast;

               -- Set tkeep for last data word as it may not be a full word
               if (rxMaster.tLast = '1') then
                  v.srpWrMaster.tKeep := genTKeep(conv_integer(r.srpReq.reqSize(1 downto 0))+1);
               else
                  v.srpWrMaster.tKeep := genTKeep(4);
               end if;

               -- Count each txn
               -- If tLast before cntSize, frameError
               -- if cntSize reached and no tlast, bleed write data, frame error
               v.txnCnt := r.txnCnt + 1;
               if r.txnCnt = r.srpReq.reqSize(31 downto 2) and rxMaster.tLast = '1' then
                  -- Done when reqSize reached and tlast
                  v.state := WAIT_ACK_S;
               elsif (r.txnCnt = r.srpReq.reqSize(31 downto 2) or rxMaster.tLast = '1') then
                  -- tLast too early or too late
                  -- Extra rxData will get blown off once IDLE_S state is reached
                  -- Due to missing SOF
                  v.state      := WAIT_ACK_S;
                  v.frameError := '1';
               end if;
            end if;


            -- Check if timer enabled
            if r.timeoutSize /= 0 then
               -- Check 100 ms timer
               if r.timer = TIMEOUT_C then
                  -- Increment counter
                  v.timeoutCnt := r.timeoutCnt + 1;
                  -- Check the counter
                  if v.timeoutCnt = r.timeoutSize then
                     -- Set the flags
                     v.timeout := '1';
                     -- Next State
                     v.state   := FOOTER_S;
                  end if;
               end if;
            end if;


         ----------------------------------------------------------------------
         when WAIT_ACK_S =>
            -- Wait for final ack from downstream
            if (srpAck.done = '1') then
               v.srpReq.request := '0';
               v.memResp        := srpAck.respCode;
            end if;

            -- Wait until both request and ack.done release before proceeding to footer
            if (r.srpReq.request = '0' and srpAck.done = '0') then
               v.state := FOOTER_S;
            end if;

            -- Check if timer enabled
            if r.timeoutSize /= 0 then
               -- Check 100 ms timer
               if r.timer = TIMEOUT_C then
                  -- Increment counter
                  v.timeoutCnt := r.timeoutCnt + 1;
                  -- Check the counter
                  if v.timeoutCnt = r.timeoutSize then
                     -- Set the flags
                     v.timeout := '1';
                     -- Next State
                     v.state   := FOOTER_S;
                  end if;
               end if;
            end if;

         ----------------------------------------------------------------------
         when FOOTER_S =>
            -- Might have arrived here after timeout with request still pending
            -- Release them now
            v.srpReq.request := '0';

            -- Check if ready to move data
            if (v.txMaster.tValid = '0') then
               -- Check for posted write
               if r.srpReq.opCode /= SRP_POSTED_WRITE_C then
                  -- Set the flags
                  v.txMaster.tValid := '1';
               end if;
               -- Set the footer data
               v.txMaster.tLast               := '1';
               v.txMaster.tData(7 downto 0)   := r.memResp;
               v.txMaster.tData(8)            := r.timeout;
               v.txMaster.tData(9)            := r.eofe;
               v.txMaster.tData(10)           := r.frameError;
               v.txMaster.tData(11)           := r.verMismatch;
               v.txMaster.tData(12)           := r.reqError;
               v.txMaster.tData(13)           := r.timeout;
               v.txMaster.tData(31 downto 14) := (others => '0');
               -- Next state
               v.state                        := IDLE_S;
            end if;

      end case;

      -- Update the EOFE flag
      if (rxMaster.tLast = '1') and (v.rxSlave.tReady = '1') then
         v.eofe := ssiGetUserEofe(SRP_AXIS_CONFIG_C, rxMaster);
      end if;

      -- Combinatorial outputs before the reset
      rxSlave       <= v.rxSlave;
      srpRdSlaveInt <= v.srpRdSlave;

      -- Reset
      if (srpRst = '1') then
         v := REG_INIT_C;
      end if;

      -- Register the variable for next clock cycle
      rin <= v;

      -- Registered Outputs
      srpReq         <= r.srpReq;
      srpWrMasterInt <= r.srpWrMaster;

   end process comb;

   seq : process (srpClk) is
   begin
      if (rising_edge(srpClk)) then
         r <= rin after TPD_G;
      end if;
   end process seq;

   TX_FIFO : entity surf.AxiStreamFifoV2
      generic map (
         -- General Configurations
         TPD_G               => TPD_G,
         PIPE_STAGES_G       => PIPE_STAGES_G,
         SLAVE_READY_EN_G    => true,
         VALID_THOLD_G       => TX_VALID_THOLD_G,
         -- FIFO configurations
         SYNTH_MODE_G        => SYNTH_MODE_G,
         MEMORY_TYPE_G       => "block",
         GEN_SYNC_FIFO_G     => GEN_SYNC_FIFO_G,
         CASCADE_SIZE_G      => 1,
         FIFO_ADDR_WIDTH_G   => 9,
         -- AXI Stream Port Configurations
         SLAVE_AXI_CONFIG_G  => SRP_AXIS_CONFIG_C,
         MASTER_AXI_CONFIG_G => AXI_STREAM_CONFIG_G)
      port map (
         -- Slave Port
         sAxisClk    => srpClk,
         sAxisRst    => srpRst,
         sAxisMaster => r.txMaster,
         sAxisSlave  => txSlave,
         -- Master Port
         mAxisClk    => mAxisClk,
         mAxisRst    => mAxisRst,
         mAxisMaster => mAxisMaster,
         mAxisSlave  => mAxisSlave);

   U_Rx : entity surf.AxiStreamResize
      generic map (
         TPD_G               => TPD_G,
         SLAVE_AXI_CONFIG_G  => AXI_STREAM_CONFIG_G,
         MASTER_AXI_CONFIG_G => SRP_AXIS_CONFIG_C)
      port map (
         -- Clock and reset
         axisClk     => srpClk,
         axisRst     => srpRst,
         -- Slave Port
         sAxisMaster => srpRdMaster,
         sAxisSlave  => srpRdSlave,
         -- Master Port
         mAxisMaster => srpRdMasterInt,
         mAxisSlave  => srpRdSlaveInt);

   U_Tx : entity surf.AxiStreamResize
      generic map (
         TPD_G               => TPD_G,
         SLAVE_AXI_CONFIG_G  => SRP_AXIS_CONFIG_C,
         MASTER_AXI_CONFIG_G => AXI_STREAM_CONFIG_G)
      port map (
         -- Clock and reset
         axisClk     => srpClk,
         axisRst     => srpRst,
         -- Slave Port
         sAxisMaster => srpWrMasterInt,
         sAxisSlave  => srpWrSlaveInt,
         -- Master Port
         mAxisMaster => srpWrMaster,
         mAxisSlave  => srpWrSlave);

end rtl;

content.content:
1	-------------------------------------------------------------------------------
2	-- Title      : SRPv3 Protocol: https://confluence.slac.stanford.edu/x/cRmVD
3	-------------------------------------------------------------------------------
4	-- Company    : SLAC National Accelerator Laboratory
5	-------------------------------------------------------------------------------
6	-- Description: SLAC Register Protocol Version 3, AXI-Lite Interface
7	--
8	-- Note: This module only supports 32-bit aligned addresses and 32-bit transactions.
9	--       For non 32-bit aligned addresses or non 32-bit transactions, use
10	--       the SrpV3Axi.vhd module with the AxiToAxiLite.vhd bridge
11	-------------------------------------------------------------------------------
12	-- This file is part of 'SLAC Firmware Standard Library'.
13	-- It is subject to the license terms in the LICENSE.txt file found in the
14	-- top-level directory of this distribution and at:
15	--    https://confluence.slac.stanford.edu/display/ppareg/LICENSE.html.
16	-- No part of 'SLAC Firmware Standard Library', including this file,
17	-- may be copied, modified, propagated, or distributed except according to
18	-- the terms contained in the LICENSE.txt file.
19	-------------------------------------------------------------------------------
20	
21	library ieee;
22	use ieee.std_logic_1164.all;
23	use ieee.std_logic_arith.all;
24	use ieee.std_logic_unsigned.all;
25	
26	library surf;
27	use surf.StdRtlPkg.all;
28	use surf.AxiStreamPkg.all;
29	use surf.SsiPkg.all;
30	use surf.AxiLitePkg.all;
31	use ieee.math_real.all;
32	
33	entity SrpV3AxiLite is
34	   generic (
35	      TPD_G                 : time                    := 1 ns;
36	      INT_PIPE_STAGES_G     : natural range 0 to 16   := 1;
37	      PIPE_STAGES_G         : natural range 0 to 16   := 1;
38	      CASCADE_SIZE_G        : positive                := 1;
39	      FIFO_PAUSE_THRESH_G   : positive range 1 to 511 := 256;
40	      FIFO_SYNTH_MODE_G     : string                  := "inferred";
41	      FIFO_MEMORY_TYPE_G    : string                  := "block";
42	      FIFO_ADDR_WIDTH_G     : integer range 9 to 48   := 9;  -- Need at least 9 to avoid logjams on large txns
43	      TX_VALID_THOLD_G      : positive range 1 to 511 := 500;  -- >1 = only when frame ready or # entries
44	      TX_VALID_BURST_MODE_G : boolean                 := true;  -- only used in VALID_THOLD_G>1
45	      SLAVE_READY_EN_G      : boolean                 := false;
46	      GEN_SYNC_FIFO_G       : boolean                 := false;
47	      ENABLE_TIMER_G        : boolean                 := true;
48	      AXIL_CLK_FREQ_G       : real                    := 156.25E+6;  -- units of Hz
49	      AXI_STREAM_CONFIG_G   : AxiStreamConfigType);
50	   port (
51	      -- AXIS Slave Interface (sAxisClk domain)
52	      sAxisClk         : in  sl;
53	      sAxisRst         : in  sl;
54	      sAxisMaster      : in  AxiStreamMasterType;
55	      sAxisSlave       : out AxiStreamSlaveType;
56	      sAxisCtrl        : out AxiStreamCtrlType;
57	      -- AXIS Master Interface (mAxisClk domain)
58	      mAxisClk         : in  sl;
59	      mAxisRst         : in  sl;
60	      mAxisMaster      : out AxiStreamMasterType;
61	      mAxisSlave       : in  AxiStreamSlaveType;
62	      -- Master AXI-Lite Interface (axilClk domain)
63	      axilClk          : in  sl;
64	      axilRst          : in  sl;
65	      mAxilWriteMaster : out AxiLiteWriteMasterType;
66	      mAxilWriteSlave  : in  AxiLiteWriteSlaveType;
67	      mAxilReadMaster  : out AxiLiteReadMasterType;
68	      mAxilReadSlave   : in  AxiLiteReadSlaveType);
69	end SrpV3AxiLite;
70	
71	architecture rtl of SrpV3AxiLite is
72	
73	   constant AXIS_CONFIG_C : AxiStreamConfigType := ssiAxiStreamConfig(4, TKEEP_COMP_C, TUSER_FIRST_LAST_C, 8);
74	   constant TIMEOUT_C     : natural             := (getTimeRatio(AXIL_CLK_FREQ_G, 10.0) - 1);  -- 100 ms timeout
75	
76	   constant SRP_VERSION_C      : slv(7 downto 0) := x"03";
77	   constant NON_POSTED_READ_C  : slv(1 downto 0) := "00";
78	   constant NON_POSTED_WRITE_C : slv(1 downto 0) := "01";
79	   constant POSTED_WRITE_C     : slv(1 downto 0) := "10";
80	   constant NULL_C             : slv(1 downto 0) := "11";
81	
82	   type StateType is (
83	      IDLE_S,
84	      HDR_REQ0_S,
85	      HDR_REQ1_S,
86	      HDR_REQ2_S,
87	      HDR_REQ3_S,
88	      HDR_RESP_S,
89	      FOOTER_S,
90	      AXIL_RD_REQ_S,
91	      AXIL_RD_RESP_S,
92	      AXIL_WR_REQ_S,
93	      AXIL_WR_RESP_S);
94	
95	   type RegType is record
96	      timer            : natural range 0 to TIMEOUT_C;
97	      hdrCnt           : slv(3 downto 0);
98	      remVer           : slv(7 downto 0);
99	      opCode           : slv(1 downto 0);
100	      prot             : slv(2 downto 0);
101	      timeoutSize      : slv(7 downto 0);
102	      timeoutCnt       : slv(7 downto 0);
103	      tid              : slv(31 downto 0);
104	      tidDly           : slv(31 downto 0);  -- simulation debug only
105	      addr             : slv(63 downto 0);
106	      reqSize          : slv(31 downto 0);
107	      cnt              : slv(29 downto 0);
108	      cntSize          : slv(29 downto 0);
109	      memResp          : slv(7 downto 0);
110	      timeout          : sl;
111	      eofe             : sl;
112	      frameError       : sl;
113	      verMismatch      : sl;
114	      reqSizeError     : sl;
115	      ignoreMemResp    : sl;
116	      rxRst            : sl;
117	      overflowDet      : sl;
118	      skip             : sl;                -- simulation debug only
119	      mAxilWriteMaster : AxiLiteWriteMasterType;
120	      mAxilReadMaster  : AxiLiteReadMasterType;
121	      rxSlave          : AxiStreamSlaveType;
122	      txMaster         : AxiStreamMasterType;
123	      state            : StateType;
124	   end record RegType;
125	   constant REG_INIT_C : RegType := (
126	      timer            => 0,
127	      hdrCnt           => (others => '0'),
128	      remVer           => (others => '0'),
129	      opCode           => (others => '0'),
130	      prot             => (others => '0'),
131	      timeoutSize      => (others => '0'),
132	      timeoutCnt       => (others => '0'),
133	      tid              => (others => '0'),
134	      tidDly           => (others => '1'),
135	      addr             => (others => '0'),
136	      reqSize          => (others => '0'),
137	      cnt              => (others => '0'),
138	      cntSize          => (others => '0'),
139	      memResp          => (others => '0'),
140	      timeout          => '0',
141	      eofe             => '0',
142	      frameError       => '0',
143	      verMismatch      => '0',
144	      reqSizeError     => '0',
145	      ignoreMemResp    => '0',
146	      rxRst            => '1',
147	      overflowDet      => '0',
148	      skip             => '0',
149	      mAxilWriteMaster => AXI_LITE_WRITE_MASTER_INIT_C,
150	      mAxilReadMaster  => AXI_LITE_READ_MASTER_INIT_C,
151	      rxSlave          => AXI_STREAM_SLAVE_INIT_C,
152	      txMaster         => AXI_STREAM_MASTER_INIT_C,
153	      state            => IDLE_S);
154	
155	   signal r   : RegType := REG_INIT_C;
156	   signal rin : RegType;
157	
158	   signal axisMaster : AxiStreamMasterType;
159	   signal axisSlave  : AxiStreamSlaveType;
160	
161	   signal sCtrl : AxiStreamCtrlType;
162	
163	   signal rxMaster     : AxiStreamMasterType;
164	   signal rxSlave      : AxiStreamSlaveType;
165	   signal rxCtrl       : AxiStreamCtrlType;
166	   signal rxTLastTUser : slv(7 downto 0);
167	   signal txSlave      : AxiStreamSlaveType;
168	   signal sAxisRxRst   : sl;
169	   signal sRstTmp      : sl;
170	   signal sRst         : sl;
171	--    signal rxRstTmp     : sl;
172	--    signal rxRst        : sl;
173	
174	   -- attribute dont_touch                 : string;
175	   -- attribute dont_touch of r            : signal is "TRUE";
176	   -- attribute dont_touch of axisMaster   : signal is "TRUE";
177	   -- attribute dont_touch of axisSlave    : signal is "TRUE";
178	   -- attribute dont_touch of sCtrl        : signal is "TRUE";
179	   -- attribute dont_touch of rxMaster     : signal is "TRUE";
180	   -- attribute dont_touch of rxSlave      : signal is "TRUE";
181	   -- attribute dont_touch of rxCtrl       : signal is "TRUE";
182	   -- attribute dont_touch of rxTLastTUser : signal is "TRUE";
183	   -- attribute dont_touch of txSlave      : signal is "TRUE";
184	   -- attribute dont_touch of rst          : signal is "TRUE";
185	   -- attribute dont_touch of sRst         : signal is "TRUE";
186	   -- attribute dont_touch of rxRst        : signal is "TRUE";
187	
188	begin
189	
190	   sAxisCtrl <= sCtrl;
191	
192	--    Sync_Rst_2 : entity surf.RstSync
193	--       generic map (
194	--          TPD_G => TPD_G)
195	--       port map (
196	--          clk      => axilClk,
197	--          asyncRst => rxRstTmp,
198	--          syncRst  => rxRst);
199	
200	
201	   U_Limiter : entity surf.SsiFrameLimiter
202	      generic map (
203	         TPD_G               => TPD_G,
204	         EN_TIMEOUT_G        => false,
205	         FRAME_LIMIT_G       => integer(ceil(4116.0/real(AXI_STREAM_CONFIG_G.TDATA_BYTES_C))),  -- (20B HDR + 4096B payload)/TDATA_BYTES_C
206	         COMMON_CLK_G        => true,
207	         SLAVE_FIFO_G        => false,
208	         MASTER_FIFO_G       => false,
209	         SLAVE_READY_EN_G    => SLAVE_READY_EN_G,
210	         SLAVE_AXI_CONFIG_G  => AXI_STREAM_CONFIG_G,
211	         MASTER_AXI_CONFIG_G => AXI_STREAM_CONFIG_G)
212	      port map (
213	         -- Slave Port
214	         sAxisClk    => sAxisClk,
215	         sAxisRst    => sRst,
216	         sAxisMaster => sAxisMaster,
217	         sAxisSlave  => sAxisSlave,
218	         -- Master Port
219	         mAxisClk    => sAxisClk,
220	         mAxisRst    => sRst,
221	         mAxisMaster => axisMaster,
222	         mAxisSlave  => axisSlave);
223	
224	   RX_FIFO : entity surf.AxiStreamFifoV2
225	      generic map (
226	         -- General Configurations
227	         TPD_G               => TPD_G,
228	         INT_PIPE_STAGES_G   => INT_PIPE_STAGES_G,
229	         PIPE_STAGES_G       => PIPE_STAGES_G,
230	         SLAVE_READY_EN_G    => SLAVE_READY_EN_G,
231	         VALID_THOLD_G       => 0,      -- = 0 = only when frame ready
232	         -- FIFO configurations
233	         SYNTH_MODE_G        => FIFO_SYNTH_MODE_G,
234	         MEMORY_TYPE_G       => FIFO_MEMORY_TYPE_G,
235	         GEN_SYNC_FIFO_G     => GEN_SYNC_FIFO_G,
236	         INT_WIDTH_SELECT_G  => "CUSTOM",
237	         INT_DATA_WIDTH_G    => 16,     -- 128-bit
238	         FIFO_ADDR_WIDTH_G   => FIFO_ADDR_WIDTH_G,  -- 8kB/FIFO = 128-bits x 512 entries
239	         FIFO_FIXED_THRESH_G => true,
240	         FIFO_PAUSE_THRESH_G => FIFO_PAUSE_THRESH_G,
241	         CASCADE_SIZE_G      => CASCADE_SIZE_G,
242	         -- AXI Stream Port Configurations
243	         SLAVE_AXI_CONFIG_G  => AXI_STREAM_CONFIG_G,
244	         MASTER_AXI_CONFIG_G => AXIS_CONFIG_C)
245	      port map (
246	         -- Slave Port
247	         sAxisClk    => sAxisClk,
248	         sAxisRst    => sRst,
249	         sAxisMaster => axisMaster,
250	         sAxisSlave  => axisSlave,
251	         sAxisCtrl   => sCtrl,
252	         -- Master Port
253	         mAxisClk    => axilClk,
254	         mAxisRst    => r.rxRst,
255	         mAxisMaster => rxMaster,
256	         mAxisSlave  => rxSlave,
257	         mTLastTUser => rxTLastTUser);
258	
259	   GEN_SYNC_SLAVE : if (GEN_SYNC_FIFO_G = true) generate
260	      rxCtrl     <= sCtrl;
261	      sAxisRxRst <= r.rxRst;
262	   end generate;
263	
264	   GEN_ASYNC_SLAVE : if (GEN_SYNC_FIFO_G = false) generate
265	      Sync_Ctrl : entity surf.SynchronizerVector
266	         generic map (
267	            TPD_G   => TPD_G,
268	            WIDTH_G => 2,
269	            INIT_G  => "11")
270	         port map (
271	            clk        => axilClk,
272	            rst        => axilRst,
273	            dataIn(0)  => sCtrl.pause,
274	            dataIn(1)  => sCtrl.idle,
275	            dataOut(0) => rxCtrl.pause,
276	            dataOut(1) => rxCtrl.idle);
277	      Sync_Overflow : entity surf.SynchronizerOneShot
278	         generic map (
279	            TPD_G => TPD_G)
280	         port map (
281	            clk     => axilClk,
282	            rst     => axilRst,
283	            dataIn  => sCtrl.overflow,
284	            dataOut => rxCtrl.overflow);
285	      Sync_Rst : entity surf.RstSync
286	         generic map (
287	            TPD_G => TPD_G)
288	         port map (
289	            clk      => sAxisClk,
290	            asyncRst => r.rxRst,
291	            syncRst  => sAxisRxRst);
292	   end generate;
293	
294	   sRstTmp <= sAxisRxRst or sAxisRst;
295	
296	   Sync_Rst_1 : entity surf.RstSync
297	      generic map (
298	         TPD_G => TPD_G)
299	      port map (
300	         clk      => sAxisClk,
301	         asyncRst => sRstTmp,
302	         syncRst  => sRst);
303	
304	
305	   comb : process (axilRst, mAxilReadSlave, mAxilWriteSlave, r, rxCtrl,
306	                   rxMaster, rxTLastTUser, txSlave) is
307	      variable v : RegType;
308	   begin
309	      -- Latch the current value
310	      v := r;
311	
312	      -- Reset the flags
313	      v.rxRst   := '0';
314	      v.skip    := '0';
315	      v.rxSlave := AXI_STREAM_SLAVE_INIT_C;
316	      if txSlave.tReady = '1' then
317	         v.txMaster.tValid := '0';
318	         v.txMaster.tLast  := '0';
319	         v.txMaster.tUser  := (others => '0');
320	      end if;
321	
322	      -- Check the timer
323	      if r.timer = TIMEOUT_C then
324	         -- Reset the timer
325	         v.timer := 0;
326	      else
327	         -- Increment the timer
328	         v.timer := r.timer + 1;
329	      end if;
330	
331	      -- Check for overflow
332	      if (rxCtrl.overflow = '1') and (r.rxRst = '0') and (SLAVE_READY_EN_G = false) then
333	         -- Set the flag
334	         v.overflowDet := '1';
335	      end if;
336	
337	      -- State Machine
338	      case r.state is
339	         ----------------------------------------------------------------------
340	         when IDLE_S =>
341	            -- Reset error flags
342	            v.memResp                  := (others => '0');
343	            --v.timeout                  := '0'; <--- if timeout ever happens then latch the timeout (don't reset) to inform SW that "hardware bus lock"
344	            v.eofe                     := '0';
345	            v.frameError               := '0';
346	            v.verMismatch              := '0';
347	            v.reqSizeError             := '0';
348	            -- Reset all AXI-Lite flags
349	            v.mAxilReadMaster.arvalid  := '0';
350	            v.mAxilReadMaster.rready   := '0';
351	            v.mAxilWriteMaster.awvalid := '0';
352	            v.mAxilWriteMaster.wvalid  := '0';
353	            v.mAxilWriteMaster.bready  := '0';
354	            v.cnt                      := (others => '0');
355	            -- Check for overflow
356	            if r.overflowDet = '1' then
357	               -- Reset the flag
358	               v.overflowDet := '0';
359	               -- Reset the FIFO
360	               v.rxRst       := '1';
361	            -- Check for valid data
362	            elsif (rxMaster.tValid = '1') and (r.rxRst = '0') then
363	               -- Accept the data
364	               v.rxSlave.tReady := '1';
365	               -- Check for SOF and no EOFE
366	               if (ssiGetUserSof(AXIS_CONFIG_C, rxMaster) = '1') and (rxTLastTUser(SSI_EOFE_C) = '0') then
367	                  -- Latch the AXIS TDEST
368	                  v.txMaster.tDest := rxMaster.tDest;
369	                  -- Latch the header information
370	                  v.remVer         := rxMaster.tData(7 downto 0);
371	                  v.opCode         := rxMaster.tData(9 downto 8);
372	                  v.ignoreMemResp  := rxMaster.tData(14);
373	                  v.prot           := rxMaster.tData(23 downto 21);
374	                  v.timeoutSize    := rxMaster.tData(31 downto 24);
375	                  -- Reset other header fields
376	                  v.tid            := (others => '0');
377	                  v.addr           := (others => '0');
378	                  v.reqSize        := (others => '0');
379	                  -- Check for tLast
380	                  if (rxMaster.tLast = '1') then
381	                     -- Set the flags
382	                     v.frameError := '1';
383	                     -- Next State
384	                     v.state      := HDR_RESP_S;
385	                  else
386	                     -- Next State
387	                     v.state := HDR_REQ0_S;
388	                  end if;
389	               end if;
390	            end if;
391	         ----------------------------------------------------------------------
392	         when HDR_REQ0_S =>
393	            -- Check for valid data
394	            if rxMaster.tValid = '1' then
395	               -- Accept the data
396	               v.rxSlave.tReady   := '1';
397	               -- Latch the request header field
398	               v.tid(31 downto 0) := rxMaster.tData(31 downto 0);
399	               -- Check for tLast
400	               if rxMaster.tLast = '1' then
401	                  -- Set the flags
402	                  v.frameError := '1';
403	                  -- Next State
404	                  v.state      := HDR_RESP_S;
405	               else
406	                  -- Next State
407	                  v.state := HDR_REQ1_S;
408	               end if;
409	            end if;
410	         ----------------------------------------------------------------------
411	         when HDR_REQ1_S =>
412	            -- Check for valid data
413	            if rxMaster.tValid = '1' then
414	               -- Accept the data
415	               v.rxSlave.tReady    := '1';
416	               -- Latch the request header field
417	               v.addr(31 downto 0) := rxMaster.tData(31 downto 0);
418	               -- Check for tLast
419	               if rxMaster.tLast = '1' then
420	                  -- Set the flags
421	                  v.frameError := '1';
422	                  -- Next State
423	                  v.state      := HDR_RESP_S;
424	               else
425	                  -- Next State
426	                  v.state := HDR_REQ2_S;
427	               end if;
428	            end if;
429	         ----------------------------------------------------------------------
430	         when HDR_REQ2_S =>
431	            -- Check for valid data
432	            if rxMaster.tValid = '1' then
433	               -- Accept the data
434	               v.rxSlave.tReady     := '1';
435	               -- Latch the request header field
436	               v.addr(63 downto 32) := rxMaster.tData(31 downto 0);
437	               -- Check for tLast
438	               if rxMaster.tLast = '1' then
439	                  -- Set the flags
440	                  v.frameError := '1';
441	                  -- Next State
442	                  v.state      := HDR_RESP_S;
443	               else
444	                  -- Next State
445	                  v.state := HDR_REQ3_S;
446	               end if;
447	            end if;
448	         ----------------------------------------------------------------------
449	         when HDR_REQ3_S =>
450	            -- Check for valid data
451	            if rxMaster.tValid = '1' then
452	               -- Accept the data
453	               v.rxSlave.tReady       := '1';
454	               -- Latch the request header field
455	               v.reqSize(31 downto 0) := rxMaster.tData(31 downto 0);
456	               -- Check for no tLast
457	               if (rxMaster.tLast = '0') then
458	                  -- Check for OP-codes that should have tLast
459	                  if (r.opCode = NULL_C) or (r.opCode = NON_POSTED_READ_C) then
460	                     -- Set the flags
461	                     v.frameError := '1';
462	                  end if;
463	               else
464	                  -- Check for OP-codes that should NOT have tLast
465	                  if (r.opCode = POSTED_WRITE_C) or (r.opCode = NON_POSTED_WRITE_C) then
466	                     -- Set the flags
467	                     v.frameError := '1';
468	                  end if;
469	               end if;
470	               -- Next State
471	               v.state := HDR_RESP_S;
472	            end if;
473	         ----------------------------------------------------------------------
474	         when HDR_RESP_S =>
475	            -- Check if ready to move data
476	            if (v.txMaster.tValid = '0') then
477	               -- Check for posted write
478	               if r.opCode /= POSTED_WRITE_C then
479	                  -- Set the flag
480	                  v.txMaster.tValid := '1';
481	               end if;
482	               -- Increment the counter
483	               v.hdrCnt := r.hdrCnt + 1;
484	               -- Check the counter
485	               case (r.hdrCnt) is
486	                  when x"0" =>
487	                     -- Set SOF
488	                     ssiSetUserSof(AXIS_CONFIG_C, v.txMaster, '1');
489	                     -- Set data bus
490	                     v.txMaster.tData(7 downto 0)   := SRP_VERSION_C;
491	                     v.txMaster.tData(9 downto 8)   := r.opCode;
492	                     v.txMaster.tData(10)           := '0';  -- UnalignedAccess: 0 = not supported (only 32-bit alignment)
493	                     v.txMaster.tData(11)           := '0';  -- MinAccessSize:   0 = 32-bit (4 byte) transactions only
494	                     v.txMaster.tData(12)           := '0';  -- WriteEn:         0 = write operations are not supported
495	                     v.txMaster.tData(13)           := '0';  -- ReadEn:          0 = read operations are not supported
496	                     v.txMaster.tData(14)           := r.ignoreMemResp;
497	                     v.txMaster.tData(20 downto 15) := (others => '0');  -- Reserved
498	                     v.txMaster.tData(23 downto 21) := r.prot;
499	                     v.txMaster.tData(31 downto 24) := r.timeoutSize;
500	                  when x"1" => v.txMaster.tData(31 downto 0) := r.tid(31 downto 0);
501	                  when x"2" => v.txMaster.tData(31 downto 0) := r.addr(31 downto 0);
502	                  when x"3" => v.txMaster.tData(31 downto 0) := r.addr(63 downto 32);
503	                  when others =>
504	                     v.txMaster.tData(31 downto 0) := r.reqSize(31 downto 0);
505	                     -- Reset the counter
506	                     v.hdrCnt                      := x"0";
507	                     -- Check for NULL
508	                     if r.opCode = NULL_C then
509	                        -- Next State
510	                        v.state := FOOTER_S;
511	                     end if;
512	                     -- Check for framing error or EOFE or timeout (A.K.A. "hardware bus lock")
513	                     if (r.frameError = '1') or (r.eofe = '1') or (r.timeout = '1') then
514	                        -- Next State
515	                        v.state := FOOTER_S;
516	                     end if;
517	                     -- Check for version mismatch
518	                     if r.remVer /= SRP_VERSION_C then
519	                        -- Set the flags
520	                        v.verMismatch := '1';
521	                        -- Next State
522	                        v.state       := FOOTER_S;
523	                     end if;
524	                     -- Check for invalid reqSize with respect to writes
525	                     if ((r.opCode = NON_POSTED_WRITE_C) or (r.opCode = POSTED_WRITE_C)) and (r.reqSize(31 downto 12) /= 0) then
526	                        -- Set the flags
527	                        v.reqSizeError := '1';
528	                        -- Next State
529	                        v.state        := FOOTER_S;
530	                     end if;
531	                     -- Check for invalid address size (AXI-Lite only support 32-bit address space)
532	                     if (r.addr(63 downto 32) /= 0) then
533	                        -- Set the flags
534	                        v.memResp(7) := '1';
535	                        -- Next State
536	                        v.state      := FOOTER_S;
537	                     end if;
538	                     -- Check for non 32-bit address alignment
539	                     if r.addr(1 downto 0) /= 0 then
540	                        -- Set the flags
541	                        v.memResp(6) := '1';
542	                        -- Next State
543	                        v.state      := FOOTER_S;
544	                     end if;
545	                     -- Check for non 32-bit transaction request
546	                     if r.reqSize(1 downto 0) /= "11" then
547	                        -- Set the flags
548	                        v.memResp(5) := '1';
549	                        -- Next State
550	                        v.state      := FOOTER_S;
551	                     end if;
552	                     -- If no error or NULL found above, then proceed with read or write request
553	                     if (v.state /= FOOTER_S) then
554	                        -- Set the counter size
555	                        v.cntSize := r.reqSize(31 downto 2);
556	                        -- Check for read
557	                        if r.opCode = NON_POSTED_READ_C then
558	                           -- Next State
559	                           v.state := AXIL_RD_REQ_S;
560	                        -- Else it is a write
561	                        else
562	                           -- Next State
563	                           v.state := AXIL_WR_REQ_S;
564	                        end if;
565	                     end if;
566	               end case;
567	            end if;
568	         ----------------------------------------------------------------------
569	         when FOOTER_S =>
570	            -- Check if ready to move data
571	            if (v.txMaster.tValid = '0') then
572	               -- Check for posted write
573	               if r.opCode /= POSTED_WRITE_C then
574	                  -- Set the flags
575	                  v.txMaster.tValid := '1';
576	               end if;
577	               -- Set the footer data
578	               v.txMaster.tLast               := '1';
579	               v.txMaster.tData(7 downto 0)   := r.memResp;
580	               v.txMaster.tData(8)            := r.timeout;
581	               v.txMaster.tData(9)            := r.eofe;
582	               v.txMaster.tData(10)           := r.frameError;
583	               v.txMaster.tData(11)           := r.verMismatch;
584	               v.txMaster.tData(12)           := r.reqSizeError;
585	               v.txMaster.tData(13)           := r.timeout;
586	               v.txMaster.tData(31 downto 14) := (others => '0');
587	               -- Debugging code for chipscope
588	               v.tidDly                       := r.tid;
589	               if ((r.tidDly + 1) /= r.tid) then
590	                  v.skip := '1';
591	               end if;
592	               -- Next state
593	               v.state := IDLE_S;
594	            end if;
595	         ----------------------------------------------------------------------
596	         when AXIL_RD_REQ_S =>
597	            -- Check if ready to move data
598	            if (v.txMaster.tValid = '0') then
599	               -- Set the read address buses
600	               v.mAxilReadMaster.araddr  := r.addr(31 downto 0);
601	               -- Start AXI-Lite transaction
602	               v.mAxilReadMaster.arvalid := '1';
603	               v.mAxilReadMaster.rready  := '1';
604	               -- Update the Protection control
605	               v.mAxilReadMaster.arprot  := r.prot;
606	               -- Reset the timer
607	               v.timer                   := 0;
608	               v.timeoutCnt              := (others => '0');
609	               -- Next state
610	               v.state                   := AXIL_RD_RESP_S;
611	            end if;
612	         ----------------------------------------------------------------------
613	         when AXIL_RD_RESP_S =>
614	            -- Check if ready to move data
615	            if (v.txMaster.tValid = '0') then
616	               -- Check slave.arready flag
617	               if mAxilReadSlave.arready = '1' then
618	                  -- Reset the flag
619	                  v.mAxilReadMaster.arvalid := '0';
620	               end if;
621	               -- Check slave.rvalid flag
622	               if mAxilReadSlave.rvalid = '1' then
623	                  -- Reset the flag
624	                  v.mAxilReadMaster.rready := '0';
625	                  -- Latch the memory bus responds
626	                  if (r.ignoreMemResp = '0') then
627	                     v.memResp(1 downto 0) := mAxilReadSlave.rresp;
628	                  end if;
629	                  -- Check for a valid responds
630	                  if mAxilReadSlave.rresp = AXI_RESP_OK_C then
631	                     -- Move the data
632	                     v.txMaster.tValid             := '1';
633	                     v.txMaster.tData(31 downto 0) := mAxilReadSlave.rdata;
634	                  elsif (r.ignoreMemResp = '1') then
635	                     -- Move the data
636	                     v.txMaster.tValid             := '1';
637	                     v.txMaster.tData(31 downto 0) := (others => '1');
638	                  end if;
639	               end if;
640	               -- Check if transaction is done
641	               if (v.mAxilReadMaster.arvalid = '0') and (v.mAxilReadMaster.rready = '0') then
642	                  -- Check for memory bus error
643	                  if v.memResp /= 0 then
644	                     -- Next State
645	                     v.state := FOOTER_S;
646	                  else
647	                     -- Increment the counter
648	                     v.cnt := r.cnt + 1;
649	                     -- Check the counter
650	                     if r.cnt = r.cntSize then
651	                        -- Next State
652	                        v.state := FOOTER_S;
653	                     else
654	                        -- Increment the address
655	                        v.addr(31 downto 2) := r.addr(31 downto 2) + 1;
656	                        -- Next state
657	                        v.state             := AXIL_RD_REQ_S;
658	                     end if;
659	                  end if;
660	               end if;
661	            end if;
662	            -- Check if timer enabled
663	            if (r.timeoutSize /= 0) and ENABLE_TIMER_G then
664	               -- Check 100 ms timer
665	               if r.timer = TIMEOUT_C then
666	                  -- Increment counter
667	                  v.timeoutCnt := r.timeoutCnt + 1;
668	                  -- Check the counter
669	                  if v.timeoutCnt = r.timeoutSize then
670	                     -- Set the flags
671	                     v.timeout := '1';
672	                     -- Next State
673	                     v.state   := FOOTER_S;
674	                  end if;
675	               end if;
676	            end if;
677	         ----------------------------------------------------------------------
678	         when AXIL_WR_REQ_S =>
679	            -- Check for valid data and ready to move data
680	            if (rxMaster.tValid = '1') and (v.txMaster.tValid = '0') then
681	               -- Accept the data
682	               v.rxSlave.tReady := '1';
683	               -- Check for framing error
684	               if (rxMaster.tLast = '1') and (r.cnt /= r.cntSize) then
685	                  -- Set the flags
686	                  v.frameError := '1';
687	                  -- Next State
688	                  v.state      := FOOTER_S;
689	               -- Check for framing error
690	               elsif (rxMaster.tLast = '0') and (r.cnt = r.cntSize) then
691	                  -- Set the flags
692	                  v.frameError := '1';
693	                  -- Next State
694	                  v.state      := FOOTER_S;
695	               else
696	                  -- Check for posted write
697	                  if r.opCode /= POSTED_WRITE_C then
698	                     -- Set the flags
699	                     v.txMaster.tValid := '1';
700	                  end if;
701	                  -- Echo the write data back
702	                  v.txMaster.tData(31 downto 0) := rxMaster.tData(31 downto 0);
703	                  -- Set the write address buses
704	                  v.mAxilWriteMaster.awaddr     := r.addr(31 downto 0);
705	                  -- Set the write data bus
706	                  v.mAxilWriteMaster.wdata      := rxMaster.tData(31 downto 0);
707	                  -- Start AXI-Lite transaction
708	                  v.mAxilWriteMaster.awvalid    := '1';
709	                  v.mAxilWriteMaster.wvalid     := '1';
710	                  v.mAxilWriteMaster.bready     := '1';
711	                  -- Update the Protection control
712	                  v.mAxilWriteMaster.awprot     := r.prot;
713	                  -- Reset the timer
714	                  v.timer                       := 0;
715	                  v.timeoutCnt                  := (others => '0');
716	                  -- Next state
717	                  v.state                       := AXIL_WR_RESP_S;
718	               end if;
719	            end if;
720	         ----------------------------------------------------------------------
721	         when AXIL_WR_RESP_S =>
722	            -- Check the slave.awready flag
723	            if mAxilWriteSlave.awready = '1' then
724	               -- Reset the flag
725	               v.mAxilWriteMaster.awvalid := '0';
726	            end if;
727	            -- Check the slave.wready flag
728	            if mAxilWriteSlave.wready = '1' then
729	               -- Reset the flag
730	               v.mAxilWriteMaster.wvalid := '0';
731	            end if;
732	            -- Check the slave.bvalid flag
733	            if mAxilWriteSlave.bvalid = '1' then
734	               -- Reset the flag
735	               v.mAxilWriteMaster.bready := '0';
736	               -- Latch the memory bus responds
737	               if (r.ignoreMemResp = '0') then
738	                  v.memResp(1 downto 0) := mAxilWriteSlave.bresp;
739	               end if;
740	            end if;
741	            -- Check if transaction is done
742	            if (v.mAxilWriteMaster.awvalid = '0') and (v.mAxilWriteMaster.wvalid = '0') and (v.mAxilWriteMaster.bready = '0') then
743	               -- Check for memory bus error
744	               if v.memResp /= 0 then
745	                  -- Next State
746	                  v.state := FOOTER_S;
747	               else
748	                  -- Increment the counter
749	                  v.cnt := r.cnt + 1;
750	                  -- Check the counter
751	                  if r.cnt = r.cntSize then
752	                     -- Next State
753	                     v.state := FOOTER_S;
754	                  else
755	                     -- Increment the address
756	                     v.addr(31 downto 2) := r.addr(31 downto 2) + 1;
757	                     -- Next state
758	                     v.state             := AXIL_WR_REQ_S;
759	                  end if;
760	               end if;
761	            end if;
762	            -- Check if timer enabled
763	            if (r.timeoutSize /= 0) and ENABLE_TIMER_G then
764	               -- Check 100 ms timer
765	               if r.timer = TIMEOUT_C then
766	                  -- Increment counter
767	                  v.timeoutCnt := r.timeoutCnt + 1;
768	                  -- Check the counter
769	                  if v.timeoutCnt = r.timeoutSize then
770	                     -- Set the flags
771	                     v.timeout := '1';
772	                     -- Next State
773	                     v.state   := FOOTER_S;
774	                  end if;
775	               end if;
776	            end if;
777	      ----------------------------------------------------------------------
778	      end case;
779	
780	      -- Update the EOFE flag
781	      if (rxMaster.tLast = '1') and (v.rxSlave.tReady = '1') then
782	         v.eofe := ssiGetUserEofe(AXIS_CONFIG_C, rxMaster);
783	      end if;
784	
785	      -- Combinatorial outputs before the reset
786	      rxSlave <= v.rxSlave;
787	
788	      -- Reset
789	      if (axilRst = '1') then
790	         v := REG_INIT_C;
791	      end if;
792	
793	      -- Register the variable for next clock cycle
794	      rin <= v;
795	
796	      -- Registered Outputs
797	      mAxilWriteMaster <= r.mAxilWriteMaster;
798	      mAxilReadMaster  <= r.mAxilReadMaster;
799	--      rxRstTmp         <= r.rxRst or axilRst;
800	
801	   end process comb;
802	
803	   seq : process (axilClk) is
804	   begin
805	      if (rising_edge(axilClk)) then
806	         r <= rin after TPD_G;
807	      end if;
808	   end process seq;
809	
810	   TX_FIFO : entity surf.AxiStreamFifoV2
811	      generic map (
812	         -- General Configurations
813	         TPD_G               => TPD_G,
814	         INT_PIPE_STAGES_G   => INT_PIPE_STAGES_G,
815	         PIPE_STAGES_G       => PIPE_STAGES_G,
816	         SLAVE_READY_EN_G    => true,
817	         VALID_THOLD_G       => TX_VALID_THOLD_G,
818	         VALID_BURST_MODE_G  => TX_VALID_BURST_MODE_G,
819	         -- FIFO configurations
820	         SYNTH_MODE_G        => FIFO_SYNTH_MODE_G,
821	         MEMORY_TYPE_G       => FIFO_MEMORY_TYPE_G,
822	         GEN_SYNC_FIFO_G     => GEN_SYNC_FIFO_G,
823	         INT_WIDTH_SELECT_G  => "CUSTOM",
824	         INT_DATA_WIDTH_G    => 16,     -- 128-bit
825	         FIFO_ADDR_WIDTH_G   => FIFO_ADDR_WIDTH_G,  -- 8kB/FIFO = 128-bits x 512 entries
826	         -- AXI Stream Port Configurations
827	         SLAVE_AXI_CONFIG_G  => AXIS_CONFIG_C,
828	         MASTER_AXI_CONFIG_G => AXI_STREAM_CONFIG_G)
829	      port map (
830	         -- Slave Port
831	         sAxisClk    => axilClk,
832	         sAxisRst    => axilRst,
833	         sAxisMaster => r.txMaster,
834	         sAxisSlave  => txSlave,
835	         -- Master Port
836	         mAxisClk    => mAxisClk,
837	         mAxisRst    => mAxisRst,
838	         mAxisMaster => mAxisMaster,
839	         mAxisSlave  => mAxisSlave);
840	
841	end rtl;
842

file.content:
-------------------------------------------------------------------------------
-- Title      : SRPv3 Protocol: https://confluence.slac.stanford.edu/x/cRmVD
-------------------------------------------------------------------------------
-- Company    : SLAC National Accelerator Laboratory
-------------------------------------------------------------------------------
-- Description: SLAC Register Protocol Version 3, AXI-Lite Interface
--
-- Note: This module only supports 32-bit aligned addresses and 32-bit transactions.
--       For non 32-bit aligned addresses or non 32-bit transactions, use
--       the SrpV3Axi.vhd module with the AxiToAxiLite.vhd bridge
-------------------------------------------------------------------------------
-- This file is part of 'SLAC Firmware Standard Library'.
-- It is subject to the license terms in the LICENSE.txt file found in the
-- top-level directory of this distribution and at:
--    https://confluence.slac.stanford.edu/display/ppareg/LICENSE.html.
-- No part of 'SLAC Firmware Standard Library', including this file,
-- may be copied, modified, propagated, or distributed except according to
-- the terms contained in the LICENSE.txt file.
-------------------------------------------------------------------------------

library ieee;
use ieee.std_logic_1164.all;
use ieee.std_logic_arith.all;
use ieee.std_logic_unsigned.all;

library surf;
use surf.StdRtlPkg.all;
use surf.AxiStreamPkg.all;
use surf.SsiPkg.all;
use surf.AxiLitePkg.all;
use ieee.math_real.all;

entity SrpV3AxiLite is
   generic (
      TPD_G                 : time                    := 1 ns;
      INT_PIPE_STAGES_G     : natural range 0 to 16   := 1;
      PIPE_STAGES_G         : natural range 0 to 16   := 1;
      CASCADE_SIZE_G        : positive                := 1;
      FIFO_PAUSE_THRESH_G   : positive range 1 to 511 := 256;
      FIFO_SYNTH_MODE_G     : string                  := "inferred";
      FIFO_MEMORY_TYPE_G    : string                  := "block";
      FIFO_ADDR_WIDTH_G     : integer range 9 to 48   := 9;  -- Need at least 9 to avoid logjams on large txns
      TX_VALID_THOLD_G      : positive range 1 to 511 := 500;  -- >1 = only when frame ready or # entries
      TX_VALID_BURST_MODE_G : boolean                 := true;  -- only used in VALID_THOLD_G>1
      SLAVE_READY_EN_G      : boolean                 := false;
      GEN_SYNC_FIFO_G       : boolean                 := false;
      ENABLE_TIMER_G        : boolean                 := true;
      AXIL_CLK_FREQ_G       : real                    := 156.25E+6;  -- units of Hz
      AXI_STREAM_CONFIG_G   : AxiStreamConfigType);
   port (
      -- AXIS Slave Interface (sAxisClk domain)
      sAxisClk         : in  sl;
      sAxisRst         : in  sl;
      sAxisMaster      : in  AxiStreamMasterType;
      sAxisSlave       : out AxiStreamSlaveType;
      sAxisCtrl        : out AxiStreamCtrlType;
      -- AXIS Master Interface (mAxisClk domain)
      mAxisClk         : in  sl;
      mAxisRst         : in  sl;
      mAxisMaster      : out AxiStreamMasterType;
      mAxisSlave       : in  AxiStreamSlaveType;
      -- Master AXI-Lite Interface (axilClk domain)
      axilClk          : in  sl;
      axilRst          : in  sl;
      mAxilWriteMaster : out AxiLiteWriteMasterType;
      mAxilWriteSlave  : in  AxiLiteWriteSlaveType;
      mAxilReadMaster  : out AxiLiteReadMasterType;
      mAxilReadSlave   : in  AxiLiteReadSlaveType);
end SrpV3AxiLite;

architecture rtl of SrpV3AxiLite is

   constant AXIS_CONFIG_C : AxiStreamConfigType := ssiAxiStreamConfig(4, TKEEP_COMP_C, TUSER_FIRST_LAST_C, 8);
   constant TIMEOUT_C     : natural             := (getTimeRatio(AXIL_CLK_FREQ_G, 10.0) - 1);  -- 100 ms timeout

   constant SRP_VERSION_C      : slv(7 downto 0) := x"03";
   constant NON_POSTED_READ_C  : slv(1 downto 0) := "00";
   constant NON_POSTED_WRITE_C : slv(1 downto 0) := "01";
   constant POSTED_WRITE_C     : slv(1 downto 0) := "10";
   constant NULL_C             : slv(1 downto 0) := "11";

   type StateType is (
      IDLE_S,
      HDR_REQ0_S,
      HDR_REQ1_S,
      HDR_REQ2_S,
      HDR_REQ3_S,
      HDR_RESP_S,
      FOOTER_S,
      AXIL_RD_REQ_S,
      AXIL_RD_RESP_S,
      AXIL_WR_REQ_S,
      AXIL_WR_RESP_S);

   type RegType is record
      timer            : natural range 0 to TIMEOUT_C;
      hdrCnt           : slv(3 downto 0);
      remVer           : slv(7 downto 0);
      opCode           : slv(1 downto 0);
      prot             : slv(2 downto 0);
      timeoutSize      : slv(7 downto 0);
      timeoutCnt       : slv(7 downto 0);
      tid              : slv(31 downto 0);
      tidDly           : slv(31 downto 0);  -- simulation debug only
      addr             : slv(63 downto 0);
      reqSize          : slv(31 downto 0);
      cnt              : slv(29 downto 0);
      cntSize          : slv(29 downto 0);
      memResp          : slv(7 downto 0);
      timeout          : sl;
      eofe             : sl;
      frameError       : sl;
      verMismatch      : sl;
      reqSizeError     : sl;
      ignoreMemResp    : sl;
      rxRst            : sl;
      overflowDet      : sl;
      skip             : sl;                -- simulation debug only
      mAxilWriteMaster : AxiLiteWriteMasterType;
      mAxilReadMaster  : AxiLiteReadMasterType;
      rxSlave          : AxiStreamSlaveType;
      txMaster         : AxiStreamMasterType;
      state            : StateType;
   end record RegType;
   constant REG_INIT_C : RegType := (
      timer            => 0,
      hdrCnt           => (others => '0'),
      remVer           => (others => '0'),
      opCode           => (others => '0'),
      prot             => (others => '0'),
      timeoutSize      => (others => '0'),
      timeoutCnt       => (others => '0'),
      tid              => (others => '0'),
      tidDly           => (others => '1'),
      addr             => (others => '0'),
      reqSize          => (others => '0'),
      cnt              => (others => '0'),
      cntSize          => (others => '0'),
      memResp          => (others => '0'),
      timeout          => '0',
      eofe             => '0',
      frameError       => '0',
      verMismatch      => '0',
      reqSizeError     => '0',
      ignoreMemResp    => '0',
      rxRst            => '1',
      overflowDet      => '0',
      skip             => '0',
      mAxilWriteMaster => AXI_LITE_WRITE_MASTER_INIT_C,
      mAxilReadMaster  => AXI_LITE_READ_MASTER_INIT_C,
      rxSlave          => AXI_STREAM_SLAVE_INIT_C,
      txMaster         => AXI_STREAM_MASTER_INIT_C,
      state            => IDLE_S);

   signal r   : RegType := REG_INIT_C;
   signal rin : RegType;

   signal axisMaster : AxiStreamMasterType;
   signal axisSlave  : AxiStreamSlaveType;

   signal sCtrl : AxiStreamCtrlType;

   signal rxMaster     : AxiStreamMasterType;
   signal rxSlave      : AxiStreamSlaveType;
   signal rxCtrl       : AxiStreamCtrlType;
   signal rxTLastTUser : slv(7 downto 0);
   signal txSlave      : AxiStreamSlaveType;
   signal sAxisRxRst   : sl;
   signal sRstTmp      : sl;
   signal sRst         : sl;
--    signal rxRstTmp     : sl;
--    signal rxRst        : sl;

   -- attribute dont_touch                 : string;
   -- attribute dont_touch of r            : signal is "TRUE";
   -- attribute dont_touch of axisMaster   : signal is "TRUE";
   -- attribute dont_touch of axisSlave    : signal is "TRUE";
   -- attribute dont_touch of sCtrl        : signal is "TRUE";
   -- attribute dont_touch of rxMaster     : signal is "TRUE";
   -- attribute dont_touch of rxSlave      : signal is "TRUE";
   -- attribute dont_touch of rxCtrl       : signal is "TRUE";
   -- attribute dont_touch of rxTLastTUser : signal is "TRUE";
   -- attribute dont_touch of txSlave      : signal is "TRUE";
   -- attribute dont_touch of rst          : signal is "TRUE";
   -- attribute dont_touch of sRst         : signal is "TRUE";
   -- attribute dont_touch of rxRst        : signal is "TRUE";

begin

   sAxisCtrl <= sCtrl;

--    Sync_Rst_2 : entity surf.RstSync
--       generic map (
--          TPD_G => TPD_G)
--       port map (
--          clk      => axilClk,
--          asyncRst => rxRstTmp,
--          syncRst  => rxRst);


   U_Limiter : entity surf.SsiFrameLimiter
      generic map (
         TPD_G               => TPD_G,
         EN_TIMEOUT_G        => false,
         FRAME_LIMIT_G       => integer(ceil(4116.0/real(AXI_STREAM_CONFIG_G.TDATA_BYTES_C))),  -- (20B HDR + 4096B payload)/TDATA_BYTES_C
         COMMON_CLK_G        => true,
         SLAVE_FIFO_G        => false,
         MASTER_FIFO_G       => false,
         SLAVE_READY_EN_G    => SLAVE_READY_EN_G,
         SLAVE_AXI_CONFIG_G  => AXI_STREAM_CONFIG_G,
         MASTER_AXI_CONFIG_G => AXI_STREAM_CONFIG_G)
      port map (
         -- Slave Port
         sAxisClk    => sAxisClk,
         sAxisRst    => sRst,
         sAxisMaster => sAxisMaster,
         sAxisSlave  => sAxisSlave,
         -- Master Port
         mAxisClk    => sAxisClk,
         mAxisRst    => sRst,
         mAxisMaster => axisMaster,
         mAxisSlave  => axisSlave);

   RX_FIFO : entity surf.AxiStreamFifoV2
      generic map (
         -- General Configurations
         TPD_G               => TPD_G,
         INT_PIPE_STAGES_G   => INT_PIPE_STAGES_G,
         PIPE_STAGES_G       => PIPE_STAGES_G,
         SLAVE_READY_EN_G    => SLAVE_READY_EN_G,
         VALID_THOLD_G       => 0,      -- = 0 = only when frame ready
         -- FIFO configurations
         SYNTH_MODE_G        => FIFO_SYNTH_MODE_G,
         MEMORY_TYPE_G       => FIFO_MEMORY_TYPE_G,
         GEN_SYNC_FIFO_G     => GEN_SYNC_FIFO_G,
         INT_WIDTH_SELECT_G  => "CUSTOM",
         INT_DATA_WIDTH_G    => 16,     -- 128-bit
         FIFO_ADDR_WIDTH_G   => FIFO_ADDR_WIDTH_G,  -- 8kB/FIFO = 128-bits x 512 entries
         FIFO_FIXED_THRESH_G => true,
         FIFO_PAUSE_THRESH_G => FIFO_PAUSE_THRESH_G,
         CASCADE_SIZE_G      => CASCADE_SIZE_G,
         -- AXI Stream Port Configurations
         SLAVE_AXI_CONFIG_G  => AXI_STREAM_CONFIG_G,
         MASTER_AXI_CONFIG_G => AXIS_CONFIG_C)
      port map (
         -- Slave Port
         sAxisClk    => sAxisClk,
         sAxisRst    => sRst,
         sAxisMaster => axisMaster,
         sAxisSlave  => axisSlave,
         sAxisCtrl   => sCtrl,
         -- Master Port
         mAxisClk    => axilClk,
         mAxisRst    => r.rxRst,
         mAxisMaster => rxMaster,
         mAxisSlave  => rxSlave,
         mTLastTUser => rxTLastTUser);

   GEN_SYNC_SLAVE : if (GEN_SYNC_FIFO_G = true) generate
      rxCtrl     <= sCtrl;
      sAxisRxRst <= r.rxRst;
   end generate;

   GEN_ASYNC_SLAVE : if (GEN_SYNC_FIFO_G = false) generate
      Sync_Ctrl : entity surf.SynchronizerVector
         generic map (
            TPD_G   => TPD_G,
            WIDTH_G => 2,
            INIT_G  => "11")
         port map (
            clk        => axilClk,
            rst        => axilRst,
            dataIn(0)  => sCtrl.pause,
            dataIn(1)  => sCtrl.idle,
            dataOut(0) => rxCtrl.pause,
            dataOut(1) => rxCtrl.idle);
      Sync_Overflow : entity surf.SynchronizerOneShot
         generic map (
            TPD_G => TPD_G)
         port map (
            clk     => axilClk,
            rst     => axilRst,
            dataIn  => sCtrl.overflow,
            dataOut => rxCtrl.overflow);
      Sync_Rst : entity surf.RstSync
         generic map (
            TPD_G => TPD_G)
         port map (
            clk      => sAxisClk,
            asyncRst => r.rxRst,
            syncRst  => sAxisRxRst);
   end generate;

   sRstTmp <= sAxisRxRst or sAxisRst;

   Sync_Rst_1 : entity surf.RstSync
      generic map (
         TPD_G => TPD_G)
      port map (
         clk      => sAxisClk,
         asyncRst => sRstTmp,
         syncRst  => sRst);


   comb : process (axilRst, mAxilReadSlave, mAxilWriteSlave, r, rxCtrl,
                   rxMaster, rxTLastTUser, txSlave) is
      variable v : RegType;
   begin
      -- Latch the current value
      v := r;

      -- Reset the flags
      v.rxRst   := '0';
      v.skip    := '0';
      v.rxSlave := AXI_STREAM_SLAVE_INIT_C;
      if txSlave.tReady = '1' then
         v.txMaster.tValid := '0';
         v.txMaster.tLast  := '0';
         v.txMaster.tUser  := (others => '0');
      end if;

      -- Check the timer
      if r.timer = TIMEOUT_C then
         -- Reset the timer
         v.timer := 0;
      else
         -- Increment the timer
         v.timer := r.timer + 1;
      end if;

      -- Check for overflow
      if (rxCtrl.overflow = '1') and (r.rxRst = '0') and (SLAVE_READY_EN_G = false) then
         -- Set the flag
         v.overflowDet := '1';
      end if;

      -- State Machine
      case r.state is
         ----------------------------------------------------------------------
         when IDLE_S =>
            -- Reset error flags
            v.memResp                  := (others => '0');
            --v.timeout                  := '0'; <--- if timeout ever happens then latch the timeout (don't reset) to inform SW that "hardware bus lock"
            v.eofe                     := '0';
            v.frameError               := '0';
            v.verMismatch              := '0';
            v.reqSizeError             := '0';
            -- Reset all AXI-Lite flags
            v.mAxilReadMaster.arvalid  := '0';
            v.mAxilReadMaster.rready   := '0';
            v.mAxilWriteMaster.awvalid := '0';
            v.mAxilWriteMaster.wvalid  := '0';
            v.mAxilWriteMaster.bready  := '0';
            v.cnt                      := (others => '0');
            -- Check for overflow
            if r.overflowDet = '1' then
               -- Reset the flag
               v.overflowDet := '0';
               -- Reset the FIFO
               v.rxRst       := '1';
            -- Check for valid data
            elsif (rxMaster.tValid = '1') and (r.rxRst = '0') then
               -- Accept the data
               v.rxSlave.tReady := '1';
               -- Check for SOF and no EOFE
               if (ssiGetUserSof(AXIS_CONFIG_C, rxMaster) = '1') and (rxTLastTUser(SSI_EOFE_C) = '0') then
                  -- Latch the AXIS TDEST
                  v.txMaster.tDest := rxMaster.tDest;
                  -- Latch the header information
                  v.remVer         := rxMaster.tData(7 downto 0);
                  v.opCode         := rxMaster.tData(9 downto 8);
                  v.ignoreMemResp  := rxMaster.tData(14);
                  v.prot           := rxMaster.tData(23 downto 21);
                  v.timeoutSize    := rxMaster.tData(31 downto 24);
                  -- Reset other header fields
                  v.tid            := (others => '0');
                  v.addr           := (others => '0');
                  v.reqSize        := (others => '0');
                  -- Check for tLast
                  if (rxMaster.tLast = '1') then
                     -- Set the flags
                     v.frameError := '1';
                     -- Next State
                     v.state      := HDR_RESP_S;
                  else
                     -- Next State
                     v.state := HDR_REQ0_S;
                  end if;
               end if;
            end if;
         ----------------------------------------------------------------------
         when HDR_REQ0_S =>
            -- Check for valid data
            if rxMaster.tValid = '1' then
               -- Accept the data
               v.rxSlave.tReady   := '1';
               -- Latch the request header field
               v.tid(31 downto 0) := rxMaster.tData(31 downto 0);
               -- Check for tLast
               if rxMaster.tLast = '1' then
                  -- Set the flags
                  v.frameError := '1';
                  -- Next State
                  v.state      := HDR_RESP_S;
               else
                  -- Next State
                  v.state := HDR_REQ1_S;
               end if;
            end if;
         ----------------------------------------------------------------------
         when HDR_REQ1_S =>
            -- Check for valid data
            if rxMaster.tValid = '1' then
               -- Accept the data
               v.rxSlave.tReady    := '1';
               -- Latch the request header field
               v.addr(31 downto 0) := rxMaster.tData(31 downto 0);
               -- Check for tLast
               if rxMaster.tLast = '1' then
                  -- Set the flags
                  v.frameError := '1';
                  -- Next State
                  v.state      := HDR_RESP_S;
               else
                  -- Next State
                  v.state := HDR_REQ2_S;
               end if;
            end if;
         ----------------------------------------------------------------------
         when HDR_REQ2_S =>
            -- Check for valid data
            if rxMaster.tValid = '1' then
               -- Accept the data
               v.rxSlave.tReady     := '1';
               -- Latch the request header field
               v.addr(63 downto 32) := rxMaster.tData(31 downto 0);
               -- Check for tLast
               if rxMaster.tLast = '1' then
                  -- Set the flags
                  v.frameError := '1';
                  -- Next State
                  v.state      := HDR_RESP_S;
               else
                  -- Next State
                  v.state := HDR_REQ3_S;
               end if;
            end if;
         ----------------------------------------------------------------------
         when HDR_REQ3_S =>
            -- Check for valid data
            if rxMaster.tValid = '1' then
               -- Accept the data
               v.rxSlave.tReady       := '1';
               -- Latch the request header field
               v.reqSize(31 downto 0) := rxMaster.tData(31 downto 0);
               -- Check for no tLast
               if (rxMaster.tLast = '0') then
                  -- Check for OP-codes that should have tLast
                  if (r.opCode = NULL_C) or (r.opCode = NON_POSTED_READ_C) then
                     -- Set the flags
                     v.frameError := '1';
                  end if;
               else
                  -- Check for OP-codes that should NOT have tLast
                  if (r.opCode = POSTED_WRITE_C) or (r.opCode = NON_POSTED_WRITE_C) then
                     -- Set the flags
                     v.frameError := '1';
                  end if;
               end if;
               -- Next State
               v.state := HDR_RESP_S;
            end if;
         ----------------------------------------------------------------------
         when HDR_RESP_S =>
            -- Check if ready to move data
            if (v.txMaster.tValid = '0') then
               -- Check for posted write
               if r.opCode /= POSTED_WRITE_C then
                  -- Set the flag
                  v.txMaster.tValid := '1';
               end if;
               -- Increment the counter
               v.hdrCnt := r.hdrCnt + 1;
               -- Check the counter
               case (r.hdrCnt) is
                  when x"0" =>
                     -- Set SOF
                     ssiSetUserSof(AXIS_CONFIG_C, v.txMaster, '1');
                     -- Set data bus
                     v.txMaster.tData(7 downto 0)   := SRP_VERSION_C;
                     v.txMaster.tData(9 downto 8)   := r.opCode;
                     v.txMaster.tData(10)           := '0';  -- UnalignedAccess: 0 = not supported (only 32-bit alignment)
                     v.txMaster.tData(11)           := '0';  -- MinAccessSize:   0 = 32-bit (4 byte) transactions only
                     v.txMaster.tData(12)           := '0';  -- WriteEn:         0 = write operations are not supported
                     v.txMaster.tData(13)           := '0';  -- ReadEn:          0 = read operations are not supported
                     v.txMaster.tData(14)           := r.ignoreMemResp;
                     v.txMaster.tData(20 downto 15) := (others => '0');  -- Reserved
                     v.txMaster.tData(23 downto 21) := r.prot;
                     v.txMaster.tData(31 downto 24) := r.timeoutSize;
                  when x"1" => v.txMaster.tData(31 downto 0) := r.tid(31 downto 0);
                  when x"2" => v.txMaster.tData(31 downto 0) := r.addr(31 downto 0);
                  when x"3" => v.txMaster.tData(31 downto 0) := r.addr(63 downto 32);
                  when others =>
                     v.txMaster.tData(31 downto 0) := r.reqSize(31 downto 0);
                     -- Reset the counter
                     v.hdrCnt                      := x"0";
                     -- Check for NULL
                     if r.opCode = NULL_C then
                        -- Next State
                        v.state := FOOTER_S;
                     end if;
                     -- Check for framing error or EOFE or timeout (A.K.A. "hardware bus lock")
                     if (r.frameError = '1') or (r.eofe = '1') or (r.timeout = '1') then
                        -- Next State
                        v.state := FOOTER_S;
                     end if;
                     -- Check for version mismatch
                     if r.remVer /= SRP_VERSION_C then
                        -- Set the flags
                        v.verMismatch := '1';
                        -- Next State
                        v.state       := FOOTER_S;
                     end if;
                     -- Check for invalid reqSize with respect to writes
                     if ((r.opCode = NON_POSTED_WRITE_C) or (r.opCode = POSTED_WRITE_C)) and (r.reqSize(31 downto 12) /= 0) then
                        -- Set the flags
                        v.reqSizeError := '1';
                        -- Next State
                        v.state        := FOOTER_S;
                     end if;
                     -- Check for invalid address size (AXI-Lite only support 32-bit address space)
                     if (r.addr(63 downto 32) /= 0) then
                        -- Set the flags
                        v.memResp(7) := '1';
                        -- Next State
                        v.state      := FOOTER_S;
                     end if;
                     -- Check for non 32-bit address alignment
                     if r.addr(1 downto 0) /= 0 then
                        -- Set the flags
                        v.memResp(6) := '1';
                        -- Next State
                        v.state      := FOOTER_S;
                     end if;
                     -- Check for non 32-bit transaction request
                     if r.reqSize(1 downto 0) /= "11" then
                        -- Set the flags
                        v.memResp(5) := '1';
                        -- Next State
                        v.state      := FOOTER_S;
                     end if;
                     -- If no error or NULL found above, then proceed with read or write request
                     if (v.state /= FOOTER_S) then
                        -- Set the counter size
                        v.cntSize := r.reqSize(31 downto 2);
                        -- Check for read
                        if r.opCode = NON_POSTED_READ_C then
                           -- Next State
                           v.state := AXIL_RD_REQ_S;
                        -- Else it is a write
                        else
                           -- Next State
                           v.state := AXIL_WR_REQ_S;
                        end if;
                     end if;
               end case;
            end if;
         ----------------------------------------------------------------------
         when FOOTER_S =>
            -- Check if ready to move data
            if (v.txMaster.tValid = '0') then
               -- Check for posted write
               if r.opCode /= POSTED_WRITE_C then
                  -- Set the flags
                  v.txMaster.tValid := '1';
               end if;
               -- Set the footer data
               v.txMaster.tLast               := '1';
               v.txMaster.tData(7 downto 0)   := r.memResp;
               v.txMaster.tData(8)            := r.timeout;
               v.txMaster.tData(9)            := r.eofe;
               v.txMaster.tData(10)           := r.frameError;
               v.txMaster.tData(11)           := r.verMismatch;
               v.txMaster.tData(12)           := r.reqSizeError;
               v.txMaster.tData(13)           := r.timeout;
               v.txMaster.tData(31 downto 14) := (others => '0');
               -- Debugging code for chipscope
               v.tidDly                       := r.tid;
               if ((r.tidDly + 1) /= r.tid) then
                  v.skip := '1';
               end if;
               -- Next state
               v.state := IDLE_S;
            end if;
         ----------------------------------------------------------------------
         when AXIL_RD_REQ_S =>
            -- Check if ready to move data
            if (v.txMaster.tValid = '0') then
               -- Set the read address buses
               v.mAxilReadMaster.araddr  := r.addr(31 downto 0);
               -- Start AXI-Lite transaction
               v.mAxilReadMaster.arvalid := '1';
               v.mAxilReadMaster.rready  := '1';
               -- Update the Protection control
               v.mAxilReadMaster.arprot  := r.prot;
               -- Reset the timer
               v.timer                   := 0;
               v.timeoutCnt              := (others => '0');
               -- Next state
               v.state                   := AXIL_RD_RESP_S;
            end if;
         ----------------------------------------------------------------------
         when AXIL_RD_RESP_S =>
            -- Check if ready to move data
            if (v.txMaster.tValid = '0') then
               -- Check slave.arready flag
               if mAxilReadSlave.arready = '1' then
                  -- Reset the flag
                  v.mAxilReadMaster.arvalid := '0';
               end if;
               -- Check slave.rvalid flag
               if mAxilReadSlave.rvalid = '1' then
                  -- Reset the flag
                  v.mAxilReadMaster.rready := '0';
                  -- Latch the memory bus responds
                  if (r.ignoreMemResp = '0') then
                     v.memResp(1 downto 0) := mAxilReadSlave.rresp;
                  end if;
                  -- Check for a valid responds
                  if mAxilReadSlave.rresp = AXI_RESP_OK_C then
                     -- Move the data
                     v.txMaster.tValid             := '1';
                     v.txMaster.tData(31 downto 0) := mAxilReadSlave.rdata;
                  elsif (r.ignoreMemResp = '1') then
                     -- Move the data
                     v.txMaster.tValid             := '1';
                     v.txMaster.tData(31 downto 0) := (others => '1');
                  end if;
               end if;
               -- Check if transaction is done
               if (v.mAxilReadMaster.arvalid = '0') and (v.mAxilReadMaster.rready = '0') then
                  -- Check for memory bus error
                  if v.memResp /= 0 then
                     -- Next State
                     v.state := FOOTER_S;
                  else
                     -- Increment the counter
                     v.cnt := r.cnt + 1;
                     -- Check the counter
                     if r.cnt = r.cntSize then
                        -- Next State
                        v.state := FOOTER_S;
                     else
                        -- Increment the address
                        v.addr(31 downto 2) := r.addr(31 downto 2) + 1;
                        -- Next state
                        v.state             := AXIL_RD_REQ_S;
                     end if;
                  end if;
               end if;
            end if;
            -- Check if timer enabled
            if (r.timeoutSize /= 0) and ENABLE_TIMER_G then
               -- Check 100 ms timer
               if r.timer = TIMEOUT_C then
                  -- Increment counter
                  v.timeoutCnt := r.timeoutCnt + 1;
                  -- Check the counter
                  if v.timeoutCnt = r.timeoutSize then
                     -- Set the flags
                     v.timeout := '1';
                     -- Next State
                     v.state   := FOOTER_S;
                  end if;
               end if;
            end if;
         ----------------------------------------------------------------------
         when AXIL_WR_REQ_S =>
            -- Check for valid data and ready to move data
            if (rxMaster.tValid = '1') and (v.txMaster.tValid = '0') then
               -- Accept the data
               v.rxSlave.tReady := '1';
               -- Check for framing error
               if (rxMaster.tLast = '1') and (r.cnt /= r.cntSize) then
                  -- Set the flags
                  v.frameError := '1';
                  -- Next State
                  v.state      := FOOTER_S;
               -- Check for framing error
               elsif (rxMaster.tLast = '0') and (r.cnt = r.cntSize) then
                  -- Set the flags
                  v.frameError := '1';
                  -- Next State
                  v.state      := FOOTER_S;
               else
                  -- Check for posted write
                  if r.opCode /= POSTED_WRITE_C then
                     -- Set the flags
                     v.txMaster.tValid := '1';
                  end if;
                  -- Echo the write data back
                  v.txMaster.tData(31 downto 0) := rxMaster.tData(31 downto 0);
                  -- Set the write address buses
                  v.mAxilWriteMaster.awaddr     := r.addr(31 downto 0);
                  -- Set the write data bus
                  v.mAxilWriteMaster.wdata      := rxMaster.tData(31 downto 0);
                  -- Start AXI-Lite transaction
                  v.mAxilWriteMaster.awvalid    := '1';
                  v.mAxilWriteMaster.wvalid     := '1';
                  v.mAxilWriteMaster.bready     := '1';
                  -- Update the Protection control
                  v.mAxilWriteMaster.awprot     := r.prot;
                  -- Reset the timer
                  v.timer                       := 0;
                  v.timeoutCnt                  := (others => '0');
                  -- Next state
                  v.state                       := AXIL_WR_RESP_S;
               end if;
            end if;
         ----------------------------------------------------------------------
         when AXIL_WR_RESP_S =>
            -- Check the slave.awready flag
            if mAxilWriteSlave.awready = '1' then
               -- Reset the flag
               v.mAxilWriteMaster.awvalid := '0';
            end if;
            -- Check the slave.wready flag
            if mAxilWriteSlave.wready = '1' then
               -- Reset the flag
               v.mAxilWriteMaster.wvalid := '0';
            end if;
            -- Check the slave.bvalid flag
            if mAxilWriteSlave.bvalid = '1' then
               -- Reset the flag
               v.mAxilWriteMaster.bready := '0';
               -- Latch the memory bus responds
               if (r.ignoreMemResp = '0') then
                  v.memResp(1 downto 0) := mAxilWriteSlave.bresp;
               end if;
            end if;
            -- Check if transaction is done
            if (v.mAxilWriteMaster.awvalid = '0') and (v.mAxilWriteMaster.wvalid = '0') and (v.mAxilWriteMaster.bready = '0') then
               -- Check for memory bus error
               if v.memResp /= 0 then
                  -- Next State
                  v.state := FOOTER_S;
               else
                  -- Increment the counter
                  v.cnt := r.cnt + 1;
                  -- Check the counter
                  if r.cnt = r.cntSize then
                     -- Next State
                     v.state := FOOTER_S;
                  else
                     -- Increment the address
                     v.addr(31 downto 2) := r.addr(31 downto 2) + 1;
                     -- Next state
                     v.state             := AXIL_WR_REQ_S;
                  end if;
               end if;
            end if;
            -- Check if timer enabled
            if (r.timeoutSize /= 0) and ENABLE_TIMER_G then
               -- Check 100 ms timer
               if r.timer = TIMEOUT_C then
                  -- Increment counter
                  v.timeoutCnt := r.timeoutCnt + 1;
                  -- Check the counter
                  if v.timeoutCnt = r.timeoutSize then
                     -- Set the flags
                     v.timeout := '1';
                     -- Next State
                     v.state   := FOOTER_S;
                  end if;
               end if;
            end if;
      ----------------------------------------------------------------------
      end case;

      -- Update the EOFE flag
      if (rxMaster.tLast = '1') and (v.rxSlave.tReady = '1') then
         v.eofe := ssiGetUserEofe(AXIS_CONFIG_C, rxMaster);
      end if;

      -- Combinatorial outputs before the reset
      rxSlave <= v.rxSlave;

      -- Reset
      if (axilRst = '1') then
         v := REG_INIT_C;
      end if;

      -- Register the variable for next clock cycle
      rin <= v;

      -- Registered Outputs
      mAxilWriteMaster <= r.mAxilWriteMaster;
      mAxilReadMaster  <= r.mAxilReadMaster;
--      rxRstTmp         <= r.rxRst or axilRst;

   end process comb;

   seq : process (axilClk) is
   begin
      if (rising_edge(axilClk)) then
         r <= rin after TPD_G;
      end if;
   end process seq;

   TX_FIFO : entity surf.AxiStreamFifoV2
      generic map (
         -- General Configurations
         TPD_G               => TPD_G,
         INT_PIPE_STAGES_G   => INT_PIPE_STAGES_G,
         PIPE_STAGES_G       => PIPE_STAGES_G,
         SLAVE_READY_EN_G    => true,
         VALID_THOLD_G       => TX_VALID_THOLD_G,
         VALID_BURST_MODE_G  => TX_VALID_BURST_MODE_G,
         -- FIFO configurations
         SYNTH_MODE_G        => FIFO_SYNTH_MODE_G,
         MEMORY_TYPE_G       => FIFO_MEMORY_TYPE_G,
         GEN_SYNC_FIFO_G     => GEN_SYNC_FIFO_G,
         INT_WIDTH_SELECT_G  => "CUSTOM",
         INT_DATA_WIDTH_G    => 16,     -- 128-bit
         FIFO_ADDR_WIDTH_G   => FIFO_ADDR_WIDTH_G,  -- 8kB/FIFO = 128-bits x 512 entries
         -- AXI Stream Port Configurations
         SLAVE_AXI_CONFIG_G  => AXIS_CONFIG_C,
         MASTER_AXI_CONFIG_G => AXI_STREAM_CONFIG_G)
      port map (
         -- Slave Port
         sAxisClk    => axilClk,
         sAxisRst    => axilRst,
         sAxisMaster => r.txMaster,
         sAxisSlave  => txSlave,
         -- Master Port
         mAxisClk    => mAxisClk,
         mAxisRst    => mAxisRst,
         mAxisMaster => mAxisMaster,
         mAxisSlave  => mAxisSlave);

end rtl;

