14	
15	library ieee;
16	use ieee.std_logic_1164.all;
17	
18	library surf;
19	use surf.StdRtlPkg.all;
20	use surf.AxiLitePkg.all;
21	use surf.AxiStreamPkg.all;
22	use surf.SsiPkg.all;
23	
24	entity SrpV3AxiLiteWrapper is
25	   generic (
26	      DATA_BYTES_G : positive range 4 to 64 := 4);
27	   port (
28	      AXIS_ACLK      : in  std_logic;
29	      AXIS_ARESETN   : in  std_logic;
30	      S_AXIS_TVALID  : in  std_logic;
31	      S_AXIS_TDATA   : in  std_logic_vector((8 * DATA_BYTES_G) - 1 downto 0);
32	      S_AXIS_TKEEP   : in  std_logic_vector(DATA_BYTES_G - 1 downto 0);
33	      S_AXIS_TLAST   : in  std_logic;
34	      S_AXIS_TDEST   : in  std_logic_vector(3 downto 0);
35	      S_AXIS_TID     : in  std_logic_vector(0 downto 0);
36	      S_AXIS_TUSER   : in  std_logic_vector(1 downto 0);
37	      S_AXIS_TREADY  : out std_logic;
38	      M_AXIS_TVALID  : out std_logic;
39	      M_AXIS_TDATA   : out std_logic_vector((8 * DATA_BYTES_G) - 1 downto 0);
40	      M_AXIS_TKEEP   : out std_logic_vector(DATA_BYTES_G - 1 downto 0);
41	      M_AXIS_TLAST   : out std_logic;
42	      M_AXIS_TDEST   : out std_logic_vector(3 downto 0);
43	      M_AXIS_TID     : out std_logic_vector(0 downto 0);
44	      M_AXIS_TUSER   : out std_logic_vector(1 downto 0);
45	      M_AXIS_TREADY  : in  std_logic;
46	      M_AXIL_AWADDR  : out std_logic_vector(11 downto 0);
47	      M_AXIL_AWPROT  : out std_logic_vector(2 downto 0);
48	      M_AXIL_AWVALID : out std_logic;
49	      M_AXIL_AWREADY : in  std_logic;
50	      M_AXIL_WDATA   : out std_logic_vector(31 downto 0);
51	      M_AXIL_WSTRB   : out std_logic_vector(3 downto 0);
52	      M_AXIL_WVALID  : out std_logic;
53	      M_AXIL_WREADY  : in  std_logic;
54	      M_AXIL_BRESP   : in  std_logic_vector(1 downto 0);
55	      M_AXIL_BVALID  : in  std_logic;
56	      M_AXIL_BREADY  : out std_logic;
57	      M_AXIL_ARADDR  : out std_logic_vector(11 downto 0);
58	      M_AXIL_ARPROT  : out std_logic_vector(2 downto 0);
59	      M_AXIL_ARVALID : out std_logic;
60	      M_AXIL_ARREADY : in  std_logic;
61	      M_AXIL_RDATA   : in  std_logic_vector(31 downto 0);
62	      M_AXIL_RRESP   : in  std_logic_vector(1 downto 0);
63	      M_AXIL_RVALID  : in  std_logic;
64	      M_AXIL_RREADY  : out std_logic);
65	end entity SrpV3AxiLiteWrapper;
66	
67	architecture rtl of SrpV3AxiLiteWrapper is
68	
69	   constant TPD_C         : time                := 10 ns / 4;
70	   constant DATA_BITS_C   : positive            := 8 * DATA_BYTES_G;
71	   constant AXIS_CONFIG_C : AxiStreamConfigType := ssiAxiStreamConfig(DATA_BYTES_G);
72	
73	   signal axisRst : sl := '0';
74	
75	   signal axilWriteMaster : AxiLiteWriteMasterType := AXI_LITE_WRITE_MASTER_INIT_C;
76	   signal axilWriteSlave  : AxiLiteWriteSlaveType  := AXI_LITE_WRITE_SLAVE_INIT_C;
77	   signal axilReadMaster  : AxiLiteReadMasterType  := AXI_LITE_READ_MASTER_INIT_C;
78	   signal axilReadSlave   : AxiLiteReadSlaveType   := AXI_LITE_READ_SLAVE_INIT_C;
79	
80	   signal sAxisMaster : AxiStreamMasterType := AXI_STREAM_MASTER_INIT_C;
81	   signal sAxisSlave  : AxiStreamSlaveType  := AXI_STREAM_SLAVE_FORCE_C;
82	   signal mAxisMaster : AxiStreamMasterType := AXI_STREAM_MASTER_INIT_C;
83	   signal mAxisSlave  : AxiStreamSlaveType  := AXI_STREAM_SLAVE_FORCE_C;
84	
85	begin
86	
87	   axisRst <= not AXIS_ARESETN;
88	
89	   sAxisComb : process (S_AXIS_TDATA, S_AXIS_TDEST, S_AXIS_TKEEP, S_AXIS_TLAST, S_AXIS_TUSER, S_AXIS_TVALID) is
90	      variable v : AxiStreamMasterType;
91	   begin
92	      v                                             := AXI_STREAM_MASTER_INIT_C;
93	      v.tValid                                     := S_AXIS_TVALID;
